   1→// ── Skills page (Preact + Signals) ───────────────────────────
   2→// Note: body_html is server-rendered trusted content from SKILL.md
   3→// processed by pulldown-cmark on the Rust gateway side.
   4→
   5→import { computed, signal, useSignal } from "@preact/signals";
   6→import type { VNode } from "preact";
   7→import { render } from "preact";
   8→import { useEffect, useRef } from "preact/hooks";
   9→import { onEvent } from "../events";
  10→import { sendRpc } from "../helpers";
  11→import { updateNavCount } from "../nav-counts";
  12→import { registerPage } from "../router";
  13→import { routes } from "../routes";
  14→import * as S from "../state";
  15→import { ConfirmDialog, requestConfirm } from "../ui";
  16→
  17→// ── Types ────────────────────────────────────────────────────
  18→
  19→interface SkillSummary {
  20→	name: string;
  21→	description?: string;
  22→	category?: string;
  23→	source?: string;
  24→	enabled?: boolean;
  25→	protected?: boolean;
  26→	display_name?: string;
  27→	quarantined?: boolean;
  28→	trusted?: boolean;
  29→	drifted?: boolean;
  30→	eligible?: boolean;
  31→}
  32→interface SkillDetail extends SkillSummary {
  33→	body?: string;
  34→	body_html?: string;
  35→	author?: string;
  36→	version?: string;
  37→	homepage?: string;
  38→	source_url?: string;
  39→	commit_sha?: string;
  40→	commit_url?: string;
  41→	commit_age_days?: number;
  42→	compatibility?: string;
  43→	allowed_tools?: string[];
  44→	license?: string;
  45→	license_url?: string;
  46→	missing_bins?: string[];
  47→	install_options?: { label?: string; kind?: string }[];
  48→	requires?: { bins?: string[]; any_bins?: string[] };
  49→	provenance?: { original_source?: string; original_commit_sha?: string; imported_from?: string };
  50→	quarantine_reason?: string;
  51→}
  52→interface RepoSummary {
  53→	source: string;
  54→	skill_count: number;
  55→	enabled_count: number;
  56→	commit_sha?: string;
  57→	quarantined?: boolean;
  58→	drifted?: boolean;
  59→	orphaned?: boolean;
  60→	repo_name?: string;
  61→	provenance?: { original_source?: string; original_commit_sha?: string; imported_from?: string };
  62→	quarantine_reason?: string;
  63→}
  64→interface ToastItem {
  65→	id: number;
  66→	message: string;
  67→	type: string;
  68→}
  69→interface InstallProgress {
  70→	id: string;
  71→	source: string;
  72→	state: string;
  73→}
  74→
  75→const repos = signal<RepoSummary[]>([]);
  76→const enabledSkills = signal<SkillSummary[]>([]);
  77→const loading = signal(false);
  78→const toasts = signal<ToastItem[]>([]);
  79→let toastId = 0;
  80→const installProgresses = signal<InstallProgress[]>([]);
  81→let installProgressId = 0;
  82→
  83→let prefetchPromise: Promise<unknown> | null = null;
  84→function ensurePrefetch(): Promise<unknown> {
  85→	if (!prefetchPromise)
  86→		prefetchPromise = fetch("/api/skills")
  87→			.then((r) => r.json())
  88→			.then((data) => {
  89→				if (data.skills) enabledSkills.value = data.skills;
  90→				if (data.repos) repos.value = data.repos;
  91→				return data;
  92→			})
  93→			.catch(() => null);
  94→	return prefetchPromise;
  95→}
  96→
  97→const skillRepoMap = computed<Record<string, string>>(() => {
  98→	const map: Record<string, string> = {};
  99→	enabledSkills.value.forEach((s) => {
 100→		if (s.source) map[s.name] = s.source;
 101→	});
 102→	return map;
 103→});
 104→
 105→function showToast(message: string, type: string): void {
 106→	const id = ++toastId;
 107→	toasts.value = toasts.value.concat([{ id, message, type }]);
 108→	setTimeout(() => {
 109→		toasts.value = toasts.value.filter((t) => t.id !== id);
 110→	}, 4000);
 111→}
 112→function shortSha(sha: string | null | undefined): string {
 113→	return sha?.slice(0, 12) || "";
 114→}
 115→function startInstallProgress(source: string, id?: string): string {
 116→	const pid = id || `install-${++installProgressId}`;
 117→	if (installProgresses.value.some((p) => p.id === pid)) return pid;
 118→	installProgresses.value = [...installProgresses.value, { id: pid, source: source || "repository", state: "running" }];
 119→	return pid;
 120→}
 121→function stopInstallProgress(id: string, _ok: boolean): void {
 122→	installProgresses.value = installProgresses.value.filter((p) => p.id !== id);
 123→}
 124→
 125→function emergencyDisableAllSkills(): void {
 126→	requestConfirm("Disable all third-party skills now?", { confirmLabel: "Disable All", danger: true }).then((yes) => {
 127→		if (!yes) return;
 128→		sendRpc("skills.emergency_disable", {}).then((res) => {
 129→			if (!res?.ok) {
 130→				showToast(`Emergency disable failed: ${res?.error || "unknown"}`, "error");
 131→				return;
 132→			}
 133→			showToast(`Disabled ${(res.payload as Record<string, number>)?.skills_disabled || 0} skills`, "success");
 134→			fetchAll();
 135→		});
 136→	});
 137→}
 138→
 139→function fetchAll(): void {
 140→	loading.value = true;
 141→	fetch("/api/skills")
 142→		.then((r) => r.json())
 143→		.then((data) => {
 144→			if (data.skills) enabledSkills.value = data.skills;
 145→			if (data.repos) repos.value = data.repos;
 146→			loading.value = false;
 147→			updateNavCount("skills", (data.skills || []).length);
 148→		})
 149→		.catch(() => {
 150→			loading.value = false;
 151→		});
 152→}
 153→
 154→function doInstall(source: string): Promise<void> {
 155→	if (!(source && S.connected)) {
 156→		if (!S.connected) showToast("Not connected to gateway.", "error");
 157→		return Promise.resolve();
 158→	}
 159→	const opId = `skills-install-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
 160→	const pid = startInstallProgress(source, opId);
 161→	return sendRpc("skills.install", { source, op_id: opId }).then((res) => {
 162→		if (res?.ok) {
 163→			const p = (res.payload || {}) as Record<string, unknown[]>;
 164→			showToast(`Installed ${source} (${(p.installed || []).length} skills)`, "success");
 165→			fetchAll();
 166→			stopInstallProgress(pid, true);
 167→		} else {
 168→			showToast(`Failed: ${res?.error || "unknown error"}`, "error");
 169→			stopInstallProgress(pid, false);
 170→		}
 171→	});
 172→}
 173→function doImportBundle(path: string): Promise<void> {
 174→	if (!(path && S.connected)) {
 175→		if (!S.connected) showToast("Not connected.", "error");
 176→		return Promise.resolve();
 177→	}
 178→	return sendRpc("skills.repos.import", { path }).then((res) => {
 179→		if (res?.ok) {
 180→			const p = (res.payload || {}) as Record<string, unknown>;
 181→			showToast(`Imported ${p.repo_name || "bundle"} (${p.skill_count || 0} skills)`, "success");
 182→			fetchAll();
 183→		} else showToast(`Failed: ${res?.error || "unknown"}`, "error");
 184→	});
 185→}
 186→function doExportBundle(source: string, path: string | null): Promise<void> {
 187→	if (!(source && S.connected)) return Promise.resolve();
 188→	const params: Record<string, string> = { source };
 189→	if (path) params.path = path;
 190→	return sendRpc("skills.repos.export", params).then((res) => {
 191→		if (res?.ok) showToast(`Exported ${source}`, "success");
 192→		else showToast(`Failed: ${res?.error || "unknown"}`, "error");
 193→	});
 194→}
 195→export function doUnquarantine(source: string): Promise<void> {
 196→	if (!(source && S.connected)) return Promise.resolve();
 197→	return sendRpc("skills.repos.unquarantine", { source }).then((res) => {
 198→		if (res?.ok) {
 199→			showToast(`Cleared quarantine for ${source}`, "success");
 200→			fetchAll();
 201→		} else showToast(`Failed: ${res?.error || "unknown"}`, "error");
 202→	});
 203→}
 204→function searchSkills(source: string, query: string): Promise<SkillSummary[]> {
 205→	return fetch(`/api/skills/search?source=${encodeURIComponent(source)}&q=${encodeURIComponent(query)}`)
 206→		.then((r) => r.json())
 207→		.then((d) => d.skills || []);
 208→}
 209→
 210→function Toasts(): VNode {
 211→	return (
 212→		<div className="skills-toast-container">
 213→			{toasts.value.map((t) => {
 214→				const bg = t.type === "error" ? "var(--error, #e55)" : "var(--accent)";
 215→				return (
 216→					<div
 217→						key={t.id}
 218→						style={{
 219→							pointerEvents: "auto",
 220→							maxWidth: "420px",
 221→							padding: "10px 16px",
 222→							borderRadius: "6px",
 223→							fontSize: ".8rem",
 224→							fontWeight: 500,
 225→							color: "#fff",
 226→							background: bg,
 227→							boxShadow: "0 4px 12px rgba(0,0,0,.15)",
 228→						}}
 229→					>
 230→						{t.message}
 231→					</div>
 232→				);
 233→			})}
 234→		</div>
 235→	);
 236→}
 237→function InstallProgressBar(): VNode | null {
 238→	const items = installProgresses.value;
 239→	if (!items.length) return null;
 240→	return (
 241→		<div style={{ display: "flex", flexDirection: "column", gap: "8px" }}>
 242→			{items.map((p) => (
 243→				<div
 244→					key={p.id}
 245→					style={{
 246→						border: "1px solid var(--border)",
 247→						borderRadius: "var(--radius-sm)",
 248→						padding: "8px 10px",
 249→						background: "var(--surface)",
 250→						fontSize: ".78rem",
 251→						color: "var(--muted)",
 252→					}}
 253→				>
 254→					<strong style={{ color: "var(--text-strong)" }}>Installing {p.source}...</strong>
 255→					<div style={{ marginTop: "3px" }}>This may take a while.</div>
 256→				</div>
 257→			))}
 258→		</div>
 259→	);
 260→}
 261→
 262→function SecurityWarning(): VNode | null {
 263→	const dismissed = useSignal(!!localStorage.getItem("moltis-skills-warning-dismissed"));
 264→	if (dismissed.value) return null;
 265→	return (
 266→		<div className="skills-warn">
 267→			<div className="skills-warn-title">{"\u26a0\ufe0f"} Skills run code on your machine</div>
 268→			<div>
 269→				Skills are community-authored instructions the agent follows <strong>with your full system privileges</strong>.
 270→			</div>
 271→			<div style={{ marginTop: "6px", color: "var(--success, #4a4)" }}>
 272→				With sandbox mode enabled, execution is isolated.
 273→			</div>
 274→			<div style={{ display: "flex", gap: "8px", marginTop: "8px" }}>
 275→				<button
 276→					onClick={() => {
 277→						localStorage.setItem("moltis-skills-warning-dismissed", "1");
 278→						dismissed.value = true;
 279→					}}
 280→					style={{
 281→						background: "none",
 282→						border: "1px solid var(--border)",
 283→						borderRadius: "var(--radius-sm)",
 284→						fontSize: ".72rem",
 285→						padding: "3px 10px",
 286→						cursor: "pointer",
 287→						color: "var(--muted)",
 288→					}}
 289→				>
 290→					Dismiss
 291→				</button>
 292→				<button className="provider-btn provider-btn-danger provider-btn-sm" onClick={emergencyDisableAllSkills}>
 293→					Disable all
 294→				</button>
 295→			</div>
 296→		</div>
 297→	);
 298→}
 299→
 300→function InstallBox(): VNode {
 301→	const ref = useRef<HTMLInputElement>(null);
 302→	const installing = useSignal(false);
 303→	function go(): void {
 304→		const v = ref.current?.value.trim();
 305→		if (!v) return;
 306→		installing.value = true;
 307→		doInstall(v).then(() => {
 308→			installing.value = false;
 309→			if (ref.current) ref.current.value = "";
 310→		});
 311→	}
 312→	return (
 313→		<div className="skills-install-box">
 314→			<input
 315→				ref={ref}
 316→				type="text"
 317→				placeholder="owner/repo or full URL (e.g. anthropics/skills)"
 318→				className="skills-install-input"
 319→				onKeyDown={(e) => {
 320→					if ((e as KeyboardEvent).key === "Enter") go();
 321→				}}
 322→			/>
 323→			<button className="provider-btn" onClick={go} disabled={installing.value}>
 324→				{installing.value ? "Installing\u2026" : "Install"}
 325→			</button>
 326→		</div>
 327→	);
 328→}
 329→function BundleTransferBox(): VNode {
 330→	const ref = useRef<HTMLInputElement>(null);
 331→	const importing = useSignal(false);
 332→	function go(): void {
 333→		const p = ref.current?.value.trim();
 334→		if (!p) return;
 335→		importing.value = true;
 336→		doImportBundle(p).finally(() => {
 337→			importing.value = false;
 338→		});
 339→	}
 340→	return (
 341→		<div className="skills-install-box">
 342→			<input
 343→				ref={ref}
 344→				type="text"
 345→				placeholder="/path/to/skill-bundle.tar.gz"
 346→				className="skills-install-input"
 347→				onKeyDown={(e) => {
 348→					if ((e as KeyboardEvent).key === "Enter") go();
 349→				}}
 350→			/>
 351→			<button className="provider-btn provider-btn-secondary" onClick={go} disabled={importing.value}>
 352→				{importing.value ? "Importing\u2026" : "Import Bundle"}
 353→			</button>
 354→		</div>
 355→	);
 356→}
 357→
 358→const featuredSkills = [
 359→	{ repo: "openclaw/skills", desc: "Community skills from ClawdHub" },
 360→	{ repo: "anthropics/skills", desc: "Official Anthropic agent skills" },
 361→	{ repo: "vercel-labs/agent-skills", desc: "Vercel agent skills collection" },
 362→	{ repo: "vercel-labs/skills", desc: "Vercel skills toolkit" },
 363→];
 364→function FeaturedCard({ skill: f }: { skill: { repo: string; desc: string } }): VNode {
 365→	const installing = useSignal(false);
 366→	const href = /^https?:\/\//.test(f.repo) ? f.repo : `https://github.com/${f.repo}`;
 367→	return (
 368→		<div className="skills-featured-card">
 369→			<div>
 370→				<a
 371→					href={href}
 372→					target="_blank"
 373→					rel="noopener noreferrer"
 374→					style={{
 375→						fontFamily: "var(--font-mono)",
 376→						fontSize: ".82rem",
 377→						fontWeight: 500,
 378→						color: "var(--text-strong)",
 379→						textDecoration: "none",
 380→					}}
 381→				>
 382→					{f.repo}
 383→				</a>
 384→				<div style={{ fontSize: ".75rem", color: "var(--muted)" }}>{f.desc}</div>
 385→			</div>
 386→			<button
 387→				onClick={() => {
 388→					installing.value = true;
 389→					doInstall(f.repo).then(() => {
 390→						installing.value = false;
 391→					});
 392→				}}
 393→				disabled={installing.value}
 394→				style={{
 395→					background: "var(--surface2)",
 396→					border: "1px solid var(--border)",
 397→					color: "var(--text)",
 398→					borderRadius: "var(--radius-sm)",
 399→					fontSize: ".72rem",
 400→					padding: "4px 10px",
 401→					cursor: "pointer",
 402→					whiteSpace: "nowrap",
 403→				}}
 404→			>
 405→				{installing.value ? "Installing\u2026" : "Install"}
 406→			</button>
 407→		</div>
 408→	);
 409→}
 410→function FeaturedSection(): VNode {
 411→	return (
 412→		<div className="skills-section">
 413→			<h3 className="skills-section-title">Featured Repositories</h3>
 414→			<div className="skills-featured-grid">
 415→				{featuredSkills.map((f) => (
 416→					<FeaturedCard key={f.repo} skill={f} />
 417→				))}
 418→			</div>
 419→		</div>
 420→	);
 421→}
 422→
 423→function SkillMetadata({ detail: d }: { detail: SkillDetail }): VNode | null {
 424→	if (!(d.author || d.version || d.homepage || d.source_url || d.commit_sha)) return null;
 425→	return (
 426→		<div
 427→			style={{
 428→				display: "flex",
 429→				alignItems: "center",
 430→				gap: "12px",
 431→				marginBottom: "8px",
 432→				fontSize: ".75rem",
 433→				color: "var(--muted)",
 434→				flexWrap: "wrap",
 435→			}}
 436→		>
 437→			{d.author && <span>Author: {d.author}</span>}
 438→			{d.version && <span>v{d.version}</span>}
 439→			{d.commit_sha && (
 440→				<span>
 441→					Commit: <code>{shortSha(d.commit_sha)}</code>
 442→				</span>
 443→			)}
 444→			{d.homepage && (
 445→				<a
 446→					href={d.homepage}
 447→					target="_blank"
 448→					rel="noopener noreferrer"
 449→					style={{ color: "var(--accent)", textDecoration: "none" }}
 450→				>
 451→					{d.homepage.replace(/^https?:\/\//, "")}
 452→				</a>
 453→			)}
 454→		</div>
 455→	);
 456→}
 457→
 458→function SkillDetailPanel({
 459→	detail: d,
 460→	repoSource,
 461→	onClose,
 462→	onReload,
 463→}: {
 464→	detail: SkillDetail;
 465→	repoSource?: string;
 466→	onClose: () => void;
 467→	onReload?: () => void;
 468→}): VNode | null {
 469→	const actionBusy = useSignal(false);
 470→	const bodyRef = useRef<HTMLDivElement>(null);
 471→	useEffect(() => {
 472→		if (bodyRef.current && d?.body_html) {
 473→			bodyRef.current.textContent = "";
 474→			// Safe: body_html is server-rendered trusted HTML from SKILL.md via pulldown-cmark
 475→			const tpl = document.createElement("template");
 476→			tpl.innerHTML = d.body_html;
 477→			bodyRef.current.appendChild(tpl.content);
 478→			bodyRef.current.querySelectorAll("a").forEach((a) => {
 479→				a.setAttribute("target", "_blank");
 480→				a.setAttribute("rel", "noopener");
 481→			});
 482→		}
 483→	}, [d?.body_html]);
 484→	if (!d) return null;
 485→	const isDisc = d.source === "personal" || d.source === "project";
 486→	function doToggle(): void {
 487→		actionBusy.value = true;
 488→		sendRpc(d.enabled ? "skills.skill.disable" : "skills.skill.enable", { source: repoSource, skill: d.name }).then(
 489→			(r) => {
 490→				actionBusy.value = false;
 491→				if (r?.ok) {
 492→					if (isDisc) onClose();
 493→					fetchAll();
 494→					onReload?.();
 495→				} else showToast(`Failed: ${r?.error || "unknown"}`, "error");
 496→			},
 497→		);
 498→	}
 499→	function onToggle(): void {
 500→		if (!S.connected || actionBusy.value) return;
 501→		if (isDisc && d.protected) {
 502→			showToast(`Protected`, "error");
 503→			return;
 504→		}
 505→		if (isDisc && d.enabled) {
 506→			requestConfirm(`Delete "${d.name}"?`, { confirmLabel: "Delete", danger: true }).then((y) => {
 507→				if (y) doToggle();
 508→			});
 509→			return;
 510→		}
 511→		doToggle();
 512→	}
 513→	return (
 514→		<div className="skills-detail-panel" style={{ display: "block" }}>
 515→			<div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: "8px" }}>
 516→				<span
 517→					style={{ fontFamily: "var(--font-mono)", fontSize: ".9rem", fontWeight: 600, color: "var(--text-strong)" }}
 518→				>
 519→					{d.display_name || d.name}
 520→				</span>
 521→				<div style={{ display: "flex", gap: "6px" }}>
 522→					<button
 523→						onClick={onToggle}
 524→						disabled={actionBusy.value}
 525→						className={
 526→							isDisc && d.enabled
 527→								? "provider-btn provider-btn-sm provider-btn-danger"
 528→								: "provider-btn provider-btn-sm provider-btn-secondary"
 529→						}
 530→					>
 531→						{actionBusy.value ? "..." : isDisc && d.enabled ? "Delete" : d.enabled ? "Disable" : "Enable"}
 532→					</button>
 533→					<button
 534→						onClick={onClose}
 535→						style={{ background: "none", border: "none", color: "var(--muted)", cursor: "pointer" }}
 536→					>
 537→						&times;
 538→					</button>
 539→				</div>
 540→			</div>
 541→			<SkillMetadata detail={d} />
 542→			{d.description && <p style={{ margin: "0 0 8px", fontSize: ".82rem" }}>{d.description}</p>}
 543→			{d.body_html && (
 544→				<div
 545→					style={{
 546→						marginTop: "10px",
 547→						border: "1px solid var(--border)",
 548→						borderRadius: "var(--radius-sm)",
 549→						background: "var(--surface2)",
 550→					}}
 551→				>
 552→					<div
 553→						style={{
 554→							padding: "6px 10px",
 555→							borderBottom: "1px solid var(--border)",
 556→							fontSize: ".68rem",
 557→							color: "var(--muted)",
 558→							fontFamily: "var(--font-mono)",
 559→							textTransform: "uppercase",
 560→						}}
 561→					>
 562→						SKILL.md source
 563→					</div>
 564→					<div
 565→						ref={bodyRef}
 566→						className="skill-body-md"
 567→						style={{ padding: "10px", maxHeight: "400px", overflowY: "auto", fontSize: ".8rem", lineHeight: 1.5 }}
 568→					/>
 569→				</div>
 570→			)}
 571→			{!d.body_html && d.body && (
 572→				<div
 573→					style={{
 574→						marginTop: "10px",
 575→						border: "1px solid var(--border)",
 576→						borderRadius: "var(--radius-sm)",
 577→						background: "var(--surface2)",
 578→					}}
 579→				>
 580→					<pre
 581→						style={{
 582→							whiteSpace: "pre-wrap",
 583→							wordBreak: "break-word",
 584→							fontSize: ".78rem",
 585→							fontFamily: "var(--font-mono)",
 586→							margin: 0,
 587→							padding: "10px",
 588→							maxHeight: "400px",
 589→							overflowY: "auto",
 590→						}}
 591→					>
 592→						{d.body}
 593→					</pre>
 594→				</div>
 595→			)}
 596→		</div>
