 45→				const isLast = i === steps.length - 1;
 46→				return (
 47→					<>
 48→						<StepDot key={i} index={i} label={label} state={state} />
 49→						{!isLast && <div className={`onboarding-step-line ${i < current ? "completed" : ""}`} />}
