151→// ── SummaryStep ─────────────────────────────────────────────
152→
153→// biome-ignore lint/complexity/noExcessiveCognitiveComplexity: summary step fetches multiple data sources and renders conditional sections
154→function SummaryStep({ onBack, onFinish }: { onBack: () => void; onFinish: () => void }): VNode {
155→	const [loading, setLoading] = useState(true);
156→	const [data, setData] = useState<SummaryData | null>(null);
157→
158→	useEffect(() => {
159→		let cancelled = false;
160→
161→		// biome-ignore lint/complexity/noExcessiveCognitiveComplexity: parallel data fetches and conditional gon reads
162→		async function load(): Promise<void> {
163→			await refreshGon();
164→
165→			const identity = getGon("identity") as IdentityInfo | null;
166→			const mem = getGon("mem") as { total?: number; available?: number } | null;
167→			const update = getGon("update") as {
168→				available?: boolean;
169→				latest_version?: string;
170→				release_url?: string;
171→			} | null;
172→			const voiceEnabled = getGon("voice_enabled") === true;
173→
174→			const [providersRes, channelsRes, tailscaleRes, voiceRes, bootstrapRes] = await Promise.all([
175→				(
176→					sendRpc("providers.available", {}) as Promise<{
177→						ok?: boolean;
178→						payload?: SummaryProvider[];
179→					}>
180→				).catch(() => null),
181→				(
182→					fetchChannelStatus() as Promise<{
183→						ok?: boolean;
184→						payload?: { channels?: SummaryChannel[] };
185→					}>
186→				).catch(() => null),
187→				fetch("/api/tailscale/status")
188→					.then((r) =>
189→						r.ok
190→							? (r.json() as Promise<{
191→									tailscale_up?: boolean;
192→									installed?: boolean;
193→								}>)
194→							: null,
195→					)
196→					.catch(() => null),
197→				voiceEnabled
198→					? (
199→							fetchVoiceProviders() as Promise<{
200→								ok?: boolean;
201→								payload?: SummaryVoice;
202→							}>
203→						).catch(() => null)
204→					: Promise.resolve(null),
205→				fetch(
206→					"/api/bootstrap?include_channels=false&include_sessions=false&include_models=false&include_projects=false&include_counts=false&include_identity=false",
207→				)
208→					.then((r) =>
209→						r.ok
210→							? (r.json() as Promise<{
211→									sandbox?: { backend?: string };
212→								}>)
213→							: null,
214→					)
215→					.catch(() => null),
216→			]);
217→
218→			if (cancelled) return;
219→
220→			setData({
221→				identity,
222→				mem,
223→				update,
224→				voiceEnabled,
225→				providers: providersRes?.ok ? providersRes.payload || [] : [],
226→				channels: channelsRes?.ok ? channelsRes.payload?.channels || [] : [],
227→				tailscale: tailscaleRes,
228→				voice: voiceRes?.ok ? voiceRes.payload || { tts: [], stt: [] } : null,
229→				sandbox: bootstrapRes?.sandbox || null,
230→			});
231→			setLoading(false);
232→		}
233→
234→		load();
235→		return () => {
236→			cancelled = true;
237→		};
238→	}, []);
239→
240→	if (loading || !data) {
241→		return (
242→			<div className="flex flex-col items-center justify-center gap-3 min-h-[200px]">
243→				<div className="inline-block w-8 h-8 border-2 border-[var(--border)] border-t-[var(--accent)] rounded-full animate-spin" />
244→				<div className="text-sm text-[var(--muted)]">{t("onboarding:summary.loadingSummary")}</div>
245→			</div>
