269→								{data.identity.emoji || ""} {data.identity.name}
270→							</span>
271→						</>
272→					) : (
273→						<span className="text-[var(--warn)]">Identity not fully configured</span>
274→					)}
275→				</SummaryRow>
276→
277→				{/* LLMs */}
278→				<SummaryRow icon={configuredProviders.length > 0 ? <CheckIcon /> : <ErrorIcon />} label="LLMs">
279→					{configuredProviders.length > 0 ? (
280→						<div className="flex flex-col gap-1">
281→							<div className="flex flex-wrap gap-1">
282→								{configuredProviders.map((p) => (
283→									<span key={p.name} className="provider-item-badge configured">
284→										{p.displayName}
285→									</span>
286→								))}
287→							</div>
288→							{activeModel ? (
