296→					)}
297→				</SummaryRow>
298→
299→				{/* Channels */}
300→				<SummaryRow
301→					icon={
302→						data.channels.length > 0 ? (
303→							data.channels.some((c) => c.status === "error") ? (
304→								<ErrorIcon />
305→							) : data.channels.some((c) => c.status === "disconnected") ? (
