  1→// ── Typed RPC method registry ────────────────────────────────
  2→//
  3→// Maps every RPC method name to its response payload type so that
  4→// `sendRpc("method.name", params)` infers the correct return type
  5→// at compile time. Methods whose payload shapes are not yet fully
  6→// typed use `unknown` as a placeholder -- callers can narrow with
  7→// `as` casts until we refine the type here.
  8→
  9→import type { ModelInfo } from "./model";
 10→import type { SessionMeta } from "./session";
 11→
