 15→	"agent.identity.get": Record<string, unknown>;
 16→	"agent.identity.update": Record<string, unknown>;
 17→	"agents.delete": unknown;
 18→	"agents.identity.get": Record<string, unknown>;
 19→	"agents.identity.update": Record<string, unknown>;
 20→	"agents.identity.update_soul": unknown;
