 37→	"chat.cancel_queued": unknown;
 38→	"chat.clear": unknown;
 39→	"chat.compact": unknown;
 40→	"chat.context": unknown;
 41→	"chat.full_context": unknown;
 42→	"chat.prompt_memory.refresh": unknown;
 43→	"chat.send": unknown;
