 20→async fn active_session_key_for_ctx(ctx: &MethodContext) -> Option<String> {
 21→    if let Some(session_key) = ctx
 22→        .params
 23→        .get("_session_key")
 24→        .and_then(|v| v.as_str())
 25→        .filter(|value| !value.trim().is_empty())
 26→    {
 27→        return Some(session_key.to_string());
 28→    }
 29→    let inner = ctx.state.inner.read().await;
 30→    inner.active_sessions.get(&ctx.client_conn_id).cloned()
 31→}
 32→
 33→async fn default_agent_id_for_ctx(ctx: &MethodContext) -> String {
 34→    if let Some(ref store) = ctx.state.services.agent_persona_store {
 35→        return store
 36→            .default_id()
 37→            .await
 38→            .unwrap_or_else(|_| "main".to_string());
 39→    }
 40→    "main".to_string()
 41→}
 42→
 43→async fn agent_exists_for_ctx(ctx: &MethodContext, agent_id: &str) -> bool {
 44→    if agent_id == "main" {
 45→        return true;
 46→    }
 47→    if let Some(ref store) = ctx.state.services.agent_persona_store {
 48→        return store.get(agent_id).await.ok().flatten().is_some();
 49→    }
 50→    false
 51→}
 52→
 53→async fn resolve_session_agent_id_for_ctx(ctx: &MethodContext) -> String {
 54→    let default_id = default_agent_id_for_ctx(ctx).await;
 55→    let Some(session_key) = active_session_key_for_ctx(ctx).await else {
 56→        return default_id;
 57→    };
 58→    let Some(ref metadata) = ctx.state.services.session_metadata else {
 59→        return default_id;
 60→    };
 61→    let Some(entry) = metadata.get(&session_key).await else {
 62→        return default_id;
 63→    };
 64→    let Some(agent_id) = entry
 65→        .agent_id
 66→        .as_deref()
 67→        .map(str::trim)
 68→        .filter(|value| !value.is_empty())
 69→    else {
 70→        return default_id;
 71→    };
 72→    if agent_exists_for_ctx(ctx, agent_id).await {
 73→        return agent_id.to_string();
 74→    }
 75→    warn!(
 76→        session = %session_key,
 77→        agent_id,
 78→        fallback = %default_id,
 79→        "session references unknown agent, falling back to default"
 80→    );
 81→    let _ = metadata.set_agent_id(&session_key, Some(&default_id)).await;
 82→    default_id
 83→}
