 85→fn parse_agent_id_param(params: &serde_json::Value) -> Option<String> {
 86→    params
 87→        .get("agent_id")
 88→        .or_else(|| params.get("id"))
 89→        .and_then(|v| v.as_str())
 90→        .map(str::trim)
 91→        .filter(|value| !value.is_empty())
 92→        .map(ToString::to_string)
 93→}
 94→
 95→async fn resolve_requested_agent_id(
 96→    ctx: &MethodContext,
 97→    params: &serde_json::Value,
 98→) -> Result<String, ErrorShape> {
 99→    if let Some(id) = parse_agent_id_param(params) {
100→        if agent_exists_for_ctx(ctx, &id).await {
101→            return Ok(id);
102→        }
103→        return Err(ErrorShape::new(
104→            error_codes::INVALID_REQUEST,
105→            format!("agent '{id}' not found"),
106→        ));
107→    }
108→    Ok(default_agent_id_for_ctx(ctx).await)
109→}
