111→fn read_identity_payload_for_agent(agent_id: &str) -> serde_json::Value {
112→    let config = moltis_config::discover_and_load();
113→    let mut identity = config.identity.clone();
114→    if let Some(file_identity) = moltis_config::load_identity_for_agent(agent_id) {
115→        if file_identity.name.is_some() {
116→            identity.name = file_identity.name;
117→        }
118→        if file_identity.emoji.is_some() {
119→            identity.emoji = file_identity.emoji;
120→        }
121→        if file_identity.theme.is_some() {
122→            identity.theme = file_identity.theme;
123→        }
124→    }
125→    let user = moltis_config::resolve_user_profile_from_config(&config);
126→    let resolved_name = identity
127→        .name
128→        .clone()
129→        .unwrap_or_else(|| "moltis".to_string());
130→    let identity_path = if agent_id == "main" {
131→        let main_path = moltis_config::agent_workspace_dir("main").join("IDENTITY.md");
132→        if main_path.exists() {
133→            main_path
134→        } else {
135→            moltis_config::identity_path()
136→        }
137→    } else {
138→        moltis_config::agent_workspace_dir(agent_id).join("IDENTITY.md")
139→    };
140→    let identity_text = std::fs::read_to_string(identity_path)
141→        .ok()
142→        .and_then(|content| moltis_config::extract_yaml_frontmatter(&content).map(str::to_string));
143→    let soul = moltis_config::load_soul_for_agent(agent_id);
