171→fn normalize_relative_agent_path(path: &str) -> Result<PathBuf, ErrorShape> {
172→    let trimmed = path.trim();
173→    if trimmed.is_empty() {
174→        return Err(ErrorShape::new(
175→            error_codes::INVALID_REQUEST,
176→            "missing 'path' parameter",
177→        ));
178→    }
179→    let candidate = Path::new(trimmed);
180→    if candidate.is_absolute() {
181→        return Err(ErrorShape::new(
182→            error_codes::INVALID_REQUEST,
183→            "path must be relative",
184→        ));
185→    }
186→    for component in candidate.components() {
187→        if matches!(
188→            component,
189→            Component::ParentDir | Component::RootDir | Component::Prefix(_)
190→        ) {
191→            return Err(ErrorShape::new(
192→                error_codes::INVALID_REQUEST,
193→                "path traversal is not allowed",
194→            ));
195→        }
196→    }
197→    Ok(candidate.to_path_buf())
198→}
