322→fn should_fallback_agent_file_to_root(agent_id: &str, relative_path: &Path) -> bool {
323→    if agent_id == "main" {
324→        return true;
325→    }
326→
327→    matches!(relative_path.to_str(), Some("AGENTS.md") | Some("TOOLS.md"))
328→}
