330→fn resolve_agent_file_target(
331→    agent_id: &str,
332→    relative_path: &Path,
333→) -> Option<(PathBuf, &'static str)> {
334→    let primary = moltis_config::agent_workspace_dir(agent_id).join(relative_path);
335→    if primary.exists() {
336→        return Some((primary, "agent"));
337→    }
338→
339→    if should_fallback_agent_file_to_root(agent_id, relative_path) {
340→        let fallback = moltis_config::data_dir().join(relative_path);
341→        if fallback.exists() {
342→            return Some((fallback, "root"));
343→        }
344→    }
345→
346→    None
347→}
