349→fn workspace_prompt_file_status(
350→    agent_id: &str,
351→    file_name: &str,
352→    limit_chars: usize,
353→) -> Option<WorkspacePromptFileStatusResponse> {
354→    let relative_path = Path::new(file_name);
355→    let (path, source) = resolve_agent_file_target(agent_id, relative_path)?;
356→    let content = std::fs::read_to_string(&path).ok()?;
357→    let normalized = moltis_config::normalize_workspace_markdown_content(&content)?;
358→    let original_chars = normalized.chars().count();
359→    let size_bytes = std::fs::metadata(&path).ok().map(|meta| meta.len());
360→    Some(WorkspacePromptFileStatusResponse {
361→        path: file_name.to_string(),
362→        source,
363→        size: size_bytes,
364→        prompt_status: WorkspaceFilePromptStatus {
365→            name: file_name.to_string(),
366→            original_chars,
367→            included_chars: original_chars.min(limit_chars),
368→            limit_chars,
369→            truncated_chars: original_chars.saturating_sub(limit_chars),
370→            truncated: original_chars > limit_chars,
371→        },
372→    })
373→}
374→
375→fn workspace_prompt_files_status(agent_id: &str, limit_chars: usize) -> Vec<serde_json::Value> {
376→    ["AGENTS.md", "TOOLS.md"]
377→        .iter()
378→        .filter_map(|file_name| {
379→            workspace_prompt_file_status(agent_id, file_name, limit_chars)
380→                .and_then(|status| serde_json::to_value(status).ok())
381→        })
382→        .collect()
383→}
