385→fn read_agent_file(agent_id: &str, relative_path: &Path) -> Result<String, ErrorShape> {
386→    let (target, _) = resolve_agent_file_target(agent_id, relative_path)
387→        .ok_or_else(|| ErrorShape::new(error_codes::INVALID_REQUEST, "file not found"))?;
388→
389→    std::fs::read_to_string(target)
390→        .map_err(|e| ErrorShape::new(error_codes::UNAVAILABLE, e.to_string()))
391→}
392→
393→fn list_agent_workspace_files_recursively(
394→    root: &Path,
395→    base: &Path,
396→    files: &mut Vec<serde_json::Value>,
397→) {
398→    let Ok(entries) = std::fs::read_dir(root) else {
399→        return;
400→    };
401→    for entry in entries.flatten() {
402→        let path = entry.path();
403→        let Ok(file_type) = entry.file_type() else {
404→            continue;
405→        };
406→        if file_type.is_dir() {
407→            list_agent_workspace_files_recursively(&path, base, files);
408→            continue;
409→        }
410→        if !file_type.is_file() {
411→            continue;
412→        }
413→        if let Ok(relative) = path.strip_prefix(base) {
414→            files.push(serde_json::json!({
415→                "path": relative.to_string_lossy(),
416→                "size": entry.metadata().ok().map(|m| m.len()),
417→            }));
418→        }
419→    }
420→}
