437→async fn reload_hooks(state: &Arc<crate::state::GatewayState>) {
438→    let disabled = state.inner.read().await.disabled_hooks.clone();
439→    let session_store = state.services.session_store.as_ref();
440→    let (new_registry, new_info) =
441→        crate::server::discover_and_build_hooks(&disabled, session_store).await;
442→
443→    {
444→        let mut inner = state.inner.write().await;
445→        inner.hook_registry = new_registry;
446→        inner.discovered_hooks = new_info.clone();
447→    }
448→
449→    // Broadcast hooks.status event so connected UIs auto-refresh.
450→    broadcast(
451→        state,
452→        "hooks.status",
453→        serde_json::json!({ "hooks": new_info }),
454→        BroadcastOpts::default(),
455→    )
456→    .await;
457→}
