 36→	useEffect(() => {
 37→		if (!ref.current) return;
 38→		const active = ref.current.querySelector(".onboarding-step.active");
 39→		if (active) active.scrollIntoView({ inline: "center", block: "nearest", behavior: "smooth" });
 40→	}, [current]);
 41→	return (
 42→		<div className="onboarding-steps" ref={ref}>
 43→			{steps.map((label, i) => {
 44→				const state = i < current ? "completed" : i === current ? "active" : "";
 45→				const isLast = i === steps.length - 1;
 46→				return (
 47→					<>
 48→						<StepDot key={i} index={i} label={label} state={state} />
 49→						{!isLast && <div className={`onboarding-step-line ${i < current ? "completed" : ""}`} />}
 50→					</>
 51→				);
 52→			})}
 53→		</div>
 54→	);
 55→}
 56→
 57→function StepDot({ index, label, state }: { index: number; label: string; state: string }): VNode {
 58→	return (
 59→		<div className={`onboarding-step ${state}`}>
 60→			<div className={`onboarding-step-dot ${state}`}>
 61→				{state === "completed" ? <span className="icon icon-md icon-checkmark" /> : index + 1}
 62→			</div>
 63→			<div className="onboarding-step-label">{label}</div>
 64→		</div>
 65→	);
 66→}
