 69→
 70→const LOW_MEMORY_THRESHOLD = 2 * 1024 * 1024 * 1024;
 71→
 72→function formatMemBytes(bytes: number | null | undefined): string {
 73→	if (bytes == null) return "?";
 74→	const gb = bytes / (1024 * 1024 * 1024);
 75→	return `${gb.toFixed(1)} GB`;
 76→}
