114→// ── Summary step types ──────────────────────────────────────
115→
116→interface SummaryProvider {
117→	name: string;
118→	displayName: string;
119→	configured: boolean;
120→}
121→
122→interface SummaryChannel {
123→	type: string;
124→	account_id: string;
125→	name?: string;
126→	status: string;
127→}
128→
129→interface SummaryVoiceProvider {
130→	name: string;
131→	enabled: boolean;
132→}
133→
134→interface SummaryVoice {
135→	tts: SummaryVoiceProvider[];
136→	stt: SummaryVoiceProvider[];
137→}
138→
139→interface SummaryData {
140→	identity: IdentityInfo | null;
141→	mem: { total?: number; available?: number } | null;
142→	update: { available?: boolean; latest_version?: string; release_url?: string } | null;
143→	voiceEnabled: boolean;
144→	providers: SummaryProvider[];
145→	channels: SummaryChannel[];
146→	tailscale: { tailscale_up?: boolean; installed?: boolean } | null;
147→	voice: SummaryVoice | null;
148→	sandbox: { backend?: string } | null;
149→}
150→
151→// ── SummaryStep ─────────────────────────────────────────────
152→
153→// biome-ignore lint/complexity/noExcessiveCognitiveComplexity: summary step fetches multiple data sources and renders conditional sections
154→function SummaryStep({ onBack, onFinish }: { onBack: () => void; onFinish: () => void }): VNode {
155→	const [loading, setLoading] = useState(true);
156→	const [data, setData] = useState<SummaryData | null>(null);
157→
158→	useEffect(() => {
159→		let cancelled = false;
160→
161→		// biome-ignore lint/complexity/noExcessiveCognitiveComplexity: parallel data fetches and conditional gon reads
162→		async function load(): Promise<void> {
163→			await refreshGon();
164→
165→			const identity = getGon("identity") as IdentityInfo | null;
166→			const mem = getGon("mem") as { total?: number; available?: number } | null;
167→			const update = getGon("update") as {
168→				available?: boolean;
169→				latest_version?: string;
170→				release_url?: string;
171→			} | null;
172→			const voiceEnabled = getGon("voice_enabled") === true;
173→
174→			const [providersRes, channelsRes, tailscaleRes, voiceRes, bootstrapRes] = await Promise.all([
175→				(
176→					sendRpc("providers.available", {}) as Promise<{
177→						ok?: boolean;
178→						payload?: SummaryProvider[];
179→					}>
180→				).catch(() => null),
181→				(
182→					fetchChannelStatus() as Promise<{
183→						ok?: boolean;
184→						payload?: { channels?: SummaryChannel[] };
185→					}>
186→				).catch(() => null),
187→				fetch("/api/tailscale/status")
188→					.then((r) =>
189→						r.ok
190→							? (r.json() as Promise<{
191→									tailscale_up?: boolean;
192→									installed?: boolean;
193→								}>)
194→							: null,
195→					)
196→					.catch(() => null),
197→				voiceEnabled
198→					? (
199→							fetchVoiceProviders() as Promise<{
200→								ok?: boolean;
201→								payload?: SummaryVoice;
202→							}>
203→						).catch(() => null)
204→					: Promise.resolve(null),
205→				fetch(
206→					"/api/bootstrap?include_channels=false&include_sessions=false&include_models=false&include_projects=false&include_counts=false&include_identity=false",
207→				)
208→					.then((r) =>
209→						r.ok
210→							? (r.json() as Promise<{
211→									sandbox?: { backend?: string };
212→								}>)
213→							: null,
214→					)
215→					.catch(() => null),
216→			]);
217→
218→			if (cancelled) return;
219→
220→			setData({
221→				identity,
222→				mem,
223→				update,
224→				voiceEnabled,
225→				providers: providersRes?.ok ? providersRes.payload || [] : [],
226→				channels: channelsRes?.ok ? channelsRes.payload?.channels || [] : [],
227→				tailscale: tailscaleRes,
228→				voice: voiceRes?.ok ? voiceRes.payload || { tts: [], stt: [] } : null,
229→				sandbox: bootstrapRes?.sandbox || null,
230→			});
231→			setLoading(false);
232→		}
233→
234→		load();
235→		return () => {
236→			cancelled = true;
237→		};
238→	}, []);
239→
240→	if (loading || !data) {
241→		return (
242→			<div className="flex flex-col items-center justify-center gap-3 min-h-[200px]">
243→				<div className="inline-block w-8 h-8 border-2 border-[var(--border)] border-t-[var(--accent)] rounded-full animate-spin" />
244→				<div className="text-sm text-[var(--muted)]">{t("onboarding:summary.loadingSummary")}</div>
245→			</div>
246→		);
247→	}
248→
249→	const activeModel = localStorage.getItem("moltis-model");
250→	const configuredProviders = data.providers.filter((p) => p.configured);
251→
252→	return (
253→		<div className="flex flex-col gap-4">
254→			<h2 className="text-lg font-medium text-[var(--text-strong)]">{t("onboarding:summary.title")}</h2>
255→			<p className="text-xs text-[var(--muted)] leading-relaxed">
256→				Overview of your configuration. You can change any of these later in Settings.
257→			</p>
258→
259→			<div className="flex flex-col gap-2">
260→				{/* Identity */}
261→				<SummaryRow
262→					icon={data.identity?.user_name && data.identity?.name ? <CheckIcon /> : <WarnIcon />}
263→					label="Identity"
264→				>
265→					{data.identity?.user_name && data.identity?.name ? (
266→						<>
267→							You: <span className="font-medium text-[var(--text)]">{data.identity.user_name}</span> Agent:{" "}
268→							<span className="font-medium text-[var(--text)]">
269→								{data.identity.emoji || ""} {data.identity.name}
270→							</span>
271→						</>
272→					) : (
273→						<span className="text-[var(--warn)]">Identity not fully configured</span>
274→					)}
275→				</SummaryRow>
276→
277→				{/* LLMs */}
278→				<SummaryRow icon={configuredProviders.length > 0 ? <CheckIcon /> : <ErrorIcon />} label="LLMs">
279→					{configuredProviders.length > 0 ? (
280→						<div className="flex flex-col gap-1">
281→							<div className="flex flex-wrap gap-1">
282→								{configuredProviders.map((p) => (
283→									<span key={p.name} className="provider-item-badge configured">
284→										{p.displayName}
285→									</span>
286→								))}
287→							</div>
288→							{activeModel ? (
289→								<div>
290→									Active model: <span className="font-mono font-medium text-[var(--text)]">{activeModel}</span>
291→								</div>
292→							) : null}
293→						</div>
294→					) : (
295→						<span className="text-[var(--error)]">No LLM providers configured</span>
296→					)}
297→				</SummaryRow>
298→
299→				{/* Channels */}
300→				<SummaryRow
301→					icon={
302→						data.channels.length > 0 ? (
303→							data.channels.some((c) => c.status === "error") ? (
304→								<ErrorIcon />
305→							) : data.channels.some((c) => c.status === "disconnected") ? (
306→								<WarnIcon />
307→							) : (
308→								<CheckIcon />
309→							)
310→						) : (
311→							<InfoIcon />
312→						)
313→					}
314→					label="Channels"
315→				>
316→					{data.channels.length > 0 ? (
317→						<div className="flex flex-col gap-1">
318→							{data.channels.map((ch) => {
319→								const statusColor =
320→									ch.status === "connected" ? "var(--ok)" : ch.status === "error" ? "var(--error)" : "var(--warn)";
321→								return (
322→									<div key={ch.account_id} className="flex items-center gap-1">
323→										<span style={`color:${statusColor}`}>{"\u25CF"}</span>
324→										<span className="font-medium text-[var(--text)]">{ch.type}</span>: {ch.name || ch.account_id}
325→										<span>({ch.status})</span>
326→									</div>
327→								);
328→							})}
329→						</div>
330→					) : (
331→						<>No channels configured</>
332→					)}
333→				</SummaryRow>
334→
335→				{/* System Memory */}
336→				<SummaryRow
337→					icon={data.mem?.total && data.mem.total < LOW_MEMORY_THRESHOLD ? <WarnIcon /> : <CheckIcon />}
338→					label="System Memory"
339→				>
340→					{data.mem ? (
341→						<>
342→							Total: <span className="font-medium text-[var(--text)]">{formatMemBytes(data.mem.total)}</span> Available:{" "}
343→							<span className="font-medium text-[var(--text)]">{formatMemBytes(data.mem.available)}</span>
344→							{data.mem.total && data.mem.total < LOW_MEMORY_THRESHOLD ? (
345→								<div className="text-[var(--warn)] mt-1">
346→									Low memory detected. Consider upgrading to an instance with more RAM.
347→								</div>
348→							) : null}
349→						</>
350→					) : (
351→						<>Memory info unavailable</>
352→					)}
353→				</SummaryRow>
354→
355→				{/* Sandbox */}
356→				<SummaryRow
357→					icon={data.sandbox?.backend && data.sandbox.backend !== "none" ? <CheckIcon /> : <InfoIcon />}
358→					label="Sandbox"
359→				>
360→					{data.sandbox?.backend && data.sandbox.backend !== "none" ? (
361→						<>
362→							Backend: <span className="font-medium text-[var(--text)]">{data.sandbox.backend}</span>
363→						</>
364→					) : (
365→						<>No container runtime detected</>
366→					)}
367→				</SummaryRow>
368→
369→				{/* Version */}
370→				<SummaryRow icon={data.update?.available ? <WarnIcon /> : <CheckIcon />} label="Version">
371→					{data.update?.available ? (
372→						<>
373→							Update available:{" "}
374→							<a
375→								href={data.update.release_url || "#"}
376→								target="_blank"
377→								rel="noopener"
378→								className="text-[var(--accent)] underline font-medium"
379→							>
380→								{data.update.latest_version}
381→							</a>
382→						</>
383→					) : (
384→						<>You are running the latest version.</>
385→					)}
386→				</SummaryRow>
387→
388→				{/* Tailscale (hidden if feature not compiled) */}
389→				{data.tailscale !== null ? (
390→					<SummaryRow
391→						icon={
392→							data.tailscale?.tailscale_up ? <CheckIcon /> : data.tailscale?.installed ? <WarnIcon /> : <InfoIcon />
393→						}
394→						label="Tailscale"
395→					>
396→						{data.tailscale?.tailscale_up ? (
397→							<>Connected</>
398→						) : data.tailscale?.installed ? (
399→							<>
400→								Installed but not connected &mdash;{" "}
401→								<a href="/settings/remote-access" className="text-[var(--accent)] underline">
402→									Configure in Settings
403→								</a>
404→							</>
405→						) : (
406→							<>Not installed. Install Tailscale for secure remote access.</>
407→						)}
408→					</SummaryRow>
409→				) : null}
410→
411→				{/* Voice (hidden if not enabled) */}
412→				{data.voiceEnabled ? (
413→					<SummaryRow
414→						icon={
415→							data.voice && [...data.voice.tts, ...data.voice.stt].some((p) => p.enabled) ? <CheckIcon /> : <InfoIcon />
416→						}
417→						label="Voice"
418→					>
419→						{(() => {
420→							if (!data.voice) return <>Voice providers unavailable</>;
421→							const enabledStt = data.voice.stt.filter((p) => p.enabled).map((p) => p.name);
422→							const enabledTts = data.voice.tts.filter((p) => p.enabled).map((p) => p.name);
423→							if (enabledStt.length === 0 && enabledTts.length === 0) return <>No voice providers enabled</>;
424→							return (
425→								<div className="flex flex-col gap-0.5">
426→									{enabledStt.length > 0 ? (
427→										<div>
428→											STT: <span className="font-medium text-[var(--text)]">{enabledStt.join(", ")}</span>
429→										</div>
430→									) : null}
431→									{enabledTts.length > 0 ? (
432→										<div>
433→											TTS: <span className="font-medium text-[var(--text)]">{enabledTts.join(", ")}</span>
434→										</div>
435→									) : null}
436→								</div>
437→							);
438→						})()}
439→					</SummaryRow>
440→				) : null}
441→			</div>
442→
443→			<div className="flex flex-wrap items-center gap-3 mt-1">
444→				<button type="button" className="provider-btn provider-btn-secondary" onClick={onBack}>
445→					{t("common:actions.back")}
446→				</button>
447→				<div className="flex-1" />
448→				<button type="button" className="provider-btn" onClick={onFinish}>
449→					{data.identity?.emoji || ""} {data.identity?.name || "Your agent"}, reporting for duty
450→				</button>
451→			</div>
452→		</div>
453→	);
454→}
