456→// ── Main page component ─────────────────────────────────────
457→
458→function OnboardingPage(): VNode {
459→	const [step, setStep] = useState(-1); // -1 = checking
460→	const [authNeeded, setAuthNeeded] = useState(false);
461→	const [authSkippable, setAuthSkippable] = useState(false);
462→	const [voiceAvailable] = useState(() => getGon("voice_enabled") === true);
463→	const headerRef = useRef<HTMLElement | null>(null);
464→	const navRef = useRef<HTMLElement | null>(null);
465→	const sessionsPanelRef = useRef<HTMLElement | null>(null);
466→
467→	// Hide nav, header, and banners for standalone experience
468→	useEffect(() => {
469→		const header = document.querySelector("header") as HTMLElement | null;
470→		const nav = document.getElementById("navPanel");
471→		const sessions = document.getElementById("sessionsPanel");
472→		const burger = document.getElementById("burgerBtn");
473→		const toggle = document.getElementById("sessionsToggle");
474→		const authBanner = document.getElementById("authDisabledBanner");
475→		headerRef.current = header;
476→		navRef.current = nav;
477→		sessionsPanelRef.current = sessions;
478→
479→		if (header) header.style.display = "none";
480→		if (nav) nav.style.display = "none";
481→		if (sessions) sessions.style.display = "none";
482→		if (burger) burger.style.display = "none";
483→		if (toggle) toggle.style.display = "none";
484→		if (authBanner) authBanner.style.display = "none";
485→
486→		return () => {
487→			if (header) header.style.display = "";
488→			if (nav) nav.style.display = "";
489→			if (sessions) sessions.style.display = "";
490→			if (burger) burger.style.display = "";
491→			if (toggle) toggle.style.display = "";
492→		};
493→	}, []);
494→
495→	// Check auth status to decide whether to show step 0
496→	useEffect(() => {
497→		fetch("/api/auth/status")
498→			.then((r) => (r.ok ? r.json() : null))
499→			.then((auth: { setup_required?: boolean; auth_disabled?: boolean; localhost_only?: boolean } | null) => {
500→				if (auth?.setup_required || (auth?.auth_disabled && !auth?.localhost_only)) {
501→					setAuthNeeded(true);
502→					setAuthSkippable(!auth.setup_required);
503→					setStep(0);
504→				} else {
505→					setAuthNeeded(false);
506→					ensureWsConnected();
507→					setStep(1);
508→				}
509→			})
510→			.catch(() => {
511→				setAuthNeeded(false);
512→				ensureWsConnected();
513→				setStep(1);
514→			});
515→	}, []);
516→
517→	if (step === -1) {
518→		return (
519→			<div className="onboarding-card">
520→				<div className="text-sm text-[var(--muted)]">{t("common:status.loading")}</div>
521→			</div>
522→		);
523→	}
524→
525→	// Build step list dynamically based on auth + voice + openclaw availability
526→	const openclawDetected = getGon("openclaw_detected") === true;
527→	const allLabels = [t("onboarding:steps.security")];
528→	if (openclawDetected) allLabels.push(t("onboarding:steps.import"));
529→	allLabels.push(t("onboarding:steps.llm"));
530→	if (voiceAvailable) allLabels.push(t("onboarding:steps.voice"));
531→	allLabels.push(
532→		t("onboarding:steps.remoteAccess"),
533→		t("onboarding:steps.channel"),
534→		t("onboarding:steps.identity"),
535→		t("onboarding:steps.summary"),
536→	);
537→	const steps = authNeeded ? allLabels : allLabels.slice(1);
538→	const stepIndex = authNeeded ? step : step - 1;
539→
540→	// Compute dynamic step indices
541→	let nextIdx = 1;
542→	const importStep = openclawDetected ? nextIdx++ : -1;
543→	const llmStep = nextIdx++;
544→	const voiceStep = voiceAvailable ? nextIdx++ : -1;
545→	const remoteAccessStep = nextIdx++;
546→	const channelStep = nextIdx++;
547→	const identityStep = nextIdx++;
548→	const summaryStep = nextIdx;
549→	const lastStep = summaryStep;
550→
551→	function goNext(): void {
552→		if (step === lastStep) window.location.assign(preferredChatPath());
553→		else setStep(step + 1);
554→	}
555→
556→	function goFinish(): void {
557→		window.location.assign(preferredChatPath());
558→	}
559→
560→	function goBack(): void {
561→		if (authNeeded) setStep(Math.max(0, step - 1));
562→		else setStep(Math.max(1, step - 1));
563→	}
564→
565→	const startedAt = getGon("started_at") as number | null;
566→	const version = String(getGon("version") || "").trim();
567→
568→	return (
569→		<div className="onboarding-card">
570→			<StepIndicator steps={steps} current={stepIndex} />
571→			<div className="mt-6">
572→				{step === 0 && <AuthStep onNext={goNext} skippable={authSkippable} />}
573→				{step === importStep && <OpenClawImportStep onNext={goNext} onBack={authNeeded ? goBack : null} />}
574→				{step === llmStep && <ProviderStep onNext={goNext} onBack={authNeeded || openclawDetected ? goBack : null} />}
575→				{step === voiceStep && <VoiceStep onNext={goNext} onBack={goBack} />}
576→				{step === remoteAccessStep && <RemoteAccessStep onNext={goNext} onBack={goBack} />}
577→				{step === channelStep && <ChannelStep onNext={goNext} onBack={goBack} />}
578→				{step === identityStep && <IdentityStep onNext={goNext} onBack={goBack} />}
579→				{step === summaryStep && <SummaryStep onBack={goBack} onFinish={goFinish} />}
580→			</div>
581→			{startedAt || version ? (
582→				<div className="text-xs text-[var(--muted)] text-center mt-4 pt-3 border-t border-[var(--border)]">
583→					{startedAt ? (
584→						<span>
585→							Server started <time data-epoch-ms={startedAt} />
586→						</span>
587→					) : null}
588→					{startedAt && version ? <span> {"\u00b7"} </span> : null}
589→					{version ? (
590→						<span>
591→							{t("onboarding:summary.versionLabel")} v{version}
592→						</span>
593→					) : null}
594→				</div>
595→			) : null}
596→		</div>
597→	);
598→}
