// ── Shared types for onboarding sub-modules ──────────────────

export interface ProviderInfo {
	name: string;
	displayName: string;
	authType: string;
	configured: boolean;
	keyOptional?: boolean;
	defaultBaseUrl?: string;
	baseUrl?: string;
	model?: string;
	models?: string[];
	uiOrder?: number;
	[key: string]: unknown;
}

export interface ModelSelectorRow {
	id: string;
	displayName: string;
	provider?: string;
	supportsTools?: boolean;
	createdAt?: number;
	recommended?: boolean;
}

export interface ValidationResult {
	ok: boolean;
	message: string | null;
}

export interface OAuthInfo {
	status: string;
	uri?: string;
	code?: string;
}

export interface SysInfo {
	totalRamGb: number;
	memoryTier: string;
