	displayName: string;
	backend: string;
	minRamGb: number;
	contextWindow: number;
	suggested?: boolean;
}

export interface IdentityInfo {
	user_name?: string;
	name?: string;
	emoji?: string;
	theme?: string;
	[key: string]: unknown;
}

export interface KeyHelp {
	text: string;
	url?: string;
	label?: string;
}

export interface ProbeResult {
	error?: string;
}

export interface RawModelRow {
	id: string;
	displayName?: string;
	provider?: string;
	supportsTools?: boolean;
	createdAt?: number;
}

