 856→		for (const sk of enabledSkills.value) {
 857→			cats.add(sk.category || "other");
 858→		}
 859→		return Array.from(cats).sort();
 860→	});
 861→
 862→	// Filter skills by search query and active category
 863→	const filtered = s.filter((sk) => {
 864→		if (activeCategory.value && (sk.category || "other") !== activeCategory.value) return false;
 865→		if (searchQuery.value) {
 866→			const q = searchQuery.value.toLowerCase();
 867→			return sk.name.toLowerCase().includes(q) || (sk.description || "").toLowerCase().includes(q);
 868→		}
 869→		return true;
 870→	});
