 876→		pending.value = sk.name;
 877→		sendRpc("skills.skill.disable", { source: map[sk.name] || sk.source, skill: sk.name }).then((r) => {
 878→			pending.value = null;
 879→			if (r?.ok) {
 880→				activeDetail.value = null;
 881→				showToast(isDisc(sk) ? `Deleted ${sk.name}` : `Disabled ${sk.name}`, "success");
 882→				fetchAll();
