 901→		if (activeDetail.value?.name === sk.name) {
 902→			activeDetail.value = null;
 903→			return;
 904→		}
 905→		detailLoading.value = true;
 906→		sendRpc("skills.skill.detail", { source: map[sk.name] || sk.source, skill: sk.name }).then((r) => {
 907→			detailLoading.value = false;
 908→			if (r?.ok) activeDetail.value = r.payload as SkillDetail;
 909→		});
 910→	}
