  1→//! Bundled skills embedded in the binary at compile time.
  2→//!
  3→//! Skills live in `crates/skills/src/assets/<category>/<name>/SKILL.md` and are
  4→//! committed to the repository. In dev mode (`cargo run`) the module reads
  5→//! directly from the filesystem for instant iteration; in release builds it
  6→//! serves from the [`include_dir!`] embedded copy.
  7→//!
  8→//! This mirrors the three-tier asset strategy in `crates/web/src/assets.rs`.
  9→
 10→use std::path::{Path, PathBuf};
 11→
 12→use crate::{
 13→    parse,
 14→    types::{SkillMetadata, SkillSource},
 15→};
 16→
 17→// ── Embedded assets ─────────────────────────────────────────────────────────
 18→
 19→static BUNDLED_ASSETS: include_dir::Dir<'static> =
 20→    include_dir::include_dir!("$CARGO_MANIFEST_DIR/src/assets");
 21→
 22→// ── Asset source resolution ─────────────────────────────────────────────────
 23→
 24→enum AssetSource {
 25→    /// Read from the filesystem (dev mode: `cargo run`).
 26→    Filesystem(PathBuf),
 27→    /// Read from the compile-time embedded directory.
 28→    Embedded,
 29→}
 30→
 31→/// Store for bundled skills. Shared (via `Arc`) between the composite
 32→/// discoverer and the `ReadSkillTool`.
 33→pub struct BundledSkillStore {
 34→    source: AssetSource,
 35→}
 36→
 37→impl BundledSkillStore {
 38→    /// Create a new store, preferring the filesystem in dev mode.
 39→    #[must_use]
 40→    pub fn new() -> Self {
 41→        let cargo_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("src/assets");
 42→        let source = if cargo_dir.is_dir() {
 43→            tracing::debug!(path = %cargo_dir.display(), "bundled skills: using filesystem (dev mode)");
 44→            AssetSource::Filesystem(cargo_dir)
 45→        } else {
 46→            tracing::debug!("bundled skills: using embedded assets");
 47→            AssetSource::Embedded
 48→        };
 49→        Self { source }
 50→    }
 51→
 52→    /// Discover metadata for all bundled skills.
 53→    ///
 54→    /// Walks the assets directory two levels deep (`<category>/<skill>/SKILL.md`),
 55→    /// parses frontmatter, and tags each with [`SkillSource::Bundled`].
 56→    pub fn discover(&self) -> Vec<SkillMetadata> {
 57→        match &self.source {
 58→            AssetSource::Filesystem(dir) => discover_from_fs(dir),
 59→            AssetSource::Embedded => discover_from_embedded(),
 60→        }
 61→    }
 62→
 63→    /// Read the full body of a bundled skill by name.
 64→    pub fn read_skill(&self, name: &str) -> Option<String> {
 65→        match &self.source {
 66→            AssetSource::Filesystem(dir) => read_skill_body_fs(dir, name),
 67→            AssetSource::Embedded => read_skill_body_embedded(name),
 68→        }
 69→    }
 70→
 71→    /// Read a sidecar file from a bundled skill directory.
 72→    ///
 73→    /// Returns `Some((bytes, is_utf8))` or `None` if the file does not exist.
 74→    pub fn read_sidecar(&self, name: &str, rel_path: &str) -> Option<(Vec<u8>, bool)> {
 75→        match &self.source {
 76→            AssetSource::Filesystem(dir) => read_sidecar_fs(dir, name, rel_path),
 77→            AssetSource::Embedded => read_sidecar_embedded(name, rel_path),
 78→        }
 79→    }
 80→
 81→    /// List sidecar files for a bundled skill (references/, templates/, etc.).
 82→    pub fn list_sidecars(&self, name: &str) -> Vec<(String, u64)> {
 83→        match &self.source {
 84→            AssetSource::Filesystem(dir) => list_sidecars_fs(dir, name),
 85→            AssetSource::Embedded => list_sidecars_embedded(name),
 86→        }
 87→    }
 88→}
 89→
 90→impl Default for BundledSkillStore {
 91→    fn default() -> Self {
 92→        Self::new()
 93→    }
 94→}
 95→
 96→// ── Filesystem (dev mode) ───────────────────────────────────────────────────
 97→
 98→/// Recursively walk the assets directory for SKILL.md files on the filesystem.
 99→/// Supports arbitrary nesting (e.g. `mlops/training/axolotl/SKILL.md`).
100→fn discover_from_fs(assets_dir: &Path) -> Vec<SkillMetadata> {
101→    let mut skills = Vec::new();
102→    discover_from_fs_recursive(assets_dir, assets_dir, &mut skills);
103→    skills
104→}
105→
106→fn discover_from_fs_recursive(assets_root: &Path, dir: &Path, skills: &mut Vec<SkillMetadata>) {
107→    let Ok(entries) = std::fs::read_dir(dir) else {
108→        return;
109→    };
110→    for entry in entries.flatten() {
111→        let path = entry.path();
112→        if !path.is_dir() {
113→            continue;
114→        }
115→        let skill_md = path.join("SKILL.md");
116→        if skill_md.is_file() {
117→            let Ok(content) = std::fs::read_to_string(&skill_md) else {
118→                continue;
119→            };
120→            match parse::parse_metadata(&content, &path) {
121→                Ok(mut meta) => {
122→                    meta.source = Some(SkillSource::Bundled);
123→                    meta.category = category_from_path(assets_root, &path);
124→                    skills.push(meta);
125→                },
126→                Err(e) => {
127→                    tracing::warn!(path = %skill_md.display(), %e, "failed to parse bundled SKILL.md");
128→                },
129→            }
130→        } else {
131→            // No SKILL.md here — recurse into subdirectories (category nesting).
132→            discover_from_fs_recursive(assets_root, &path, skills);
133→        }
134→    }
135→}
136→
137→/// Extract the top-level category from a skill's path relative to the assets root.
138→/// e.g. `assets/research/arxiv` → `"research"`, `assets/mlops/training/axolotl` → `"mlops"`.
139→fn category_from_path(assets_root: &Path, skill_dir: &Path) -> Option<String> {
140→    let rel = skill_dir.strip_prefix(assets_root).ok()?;
141→    let first_component = rel.components().next()?;
142→    Some(first_component.as_os_str().to_string_lossy().into_owned())
143→}
144→
145→/// Read SKILL.md body from the filesystem.
146→fn read_skill_body_fs(assets_dir: &Path, name: &str) -> Option<String> {
147→    let skill_dir = find_skill_dir_fs(assets_dir, name)?;
148→    let content = std::fs::read_to_string(skill_dir.join("SKILL.md")).ok()?;
149→    let skill = parse::parse_skill(&content, &skill_dir).ok()?;
150→    Some(skill.body)
151→}
152→
153→fn read_sidecar_fs(assets_dir: &Path, name: &str, rel_path: &str) -> Option<(Vec<u8>, bool)> {
154→    let skill_dir = find_skill_dir_fs(assets_dir, name)?;
155→    let target = skill_dir.join(rel_path);
156→    // Basic traversal check.
157→    if !target.starts_with(&skill_dir) {
158→        return None;
159→    }
160→    let bytes = std::fs::read(&target).ok()?;
161→    let is_utf8 = std::str::from_utf8(&bytes).is_ok();
162→    Some((bytes, is_utf8))
163→}
164→
165→fn list_sidecars_fs(assets_dir: &Path, name: &str) -> Vec<(String, u64)> {
166→    let Some(skill_dir) = find_skill_dir_fs(assets_dir, name) else {
167→        return Vec::new();
168→    };
169→    let mut out = Vec::new();
170→    for sub in crate::SIDECAR_SUBDIRS {
171→        let dir = skill_dir.join(sub);
172→        let Ok(entries) = std::fs::read_dir(&dir) else {
173→            continue;
174→        };
175→        for entry in entries.flatten() {
176→            if entry.path().is_file() {
177→                let file_name = entry.file_name().to_string_lossy().to_string();
178→                let bytes = entry.metadata().map(|m| m.len()).unwrap_or(0);
179→                out.push((format!("{sub}/{file_name}"), bytes));
180→            }
181→        }
182→    }
183→    out.sort_by(|a, b| a.0.cmp(&b.0));
184→    out
185→}
186→
187→/// Recursively find a skill directory by name under the assets tree.
188→fn find_skill_dir_fs(dir: &Path, name: &str) -> Option<PathBuf> {
189→    let entries = std::fs::read_dir(dir).ok()?;
190→    for entry in entries.flatten() {
191→        let path = entry.path();
192→        if !path.is_dir() {
193→            continue;
194→        }
195→        let dir_name = path.file_name().and_then(|n| n.to_str()).unwrap_or("");
196→        if dir_name == name && path.join("SKILL.md").is_file() {
197→            return Some(path);
198→        }
199→        // Recurse into subdirectories (category nesting).
200→        if let Some(found) = find_skill_dir_fs(&path, name) {
201→            return Some(found);
202→        }
203→    }
204→    None
205→}
206→
207→// ── Embedded (release mode) ─────────────────────────────────────────────────
208→
209→/// Recursively walk the embedded `include_dir!` tree for SKILL.md files.
210→fn discover_from_embedded() -> Vec<SkillMetadata> {
211→    let mut skills = Vec::new();
212→    discover_from_embedded_recursive(&BUNDLED_ASSETS, &mut skills);
213→    skills
214→}
215→
216→fn discover_from_embedded_recursive(
217→    dir: &include_dir::Dir<'static>,
218→    skills: &mut Vec<SkillMetadata>,
219→) {
220→    for sub_dir in dir.dirs() {
221→        if let Some(skill_md) = sub_dir.get_file("SKILL.md") {
222→            let Ok(content) = std::str::from_utf8(skill_md.contents()) else {
223→                continue;
224→            };
225→            let synthetic_path =
226→                PathBuf::from("__bundled__").join(sub_dir.path().to_string_lossy().as_ref());
227→            match parse::parse_metadata(content, &synthetic_path) {
228→                Ok(mut meta) => {
229→                    meta.source = Some(SkillSource::Bundled);
230→                    // Extract category from first path component (e.g. "research/arxiv" → "research").
231→                    meta.category = sub_dir
232→                        .path()
233→                        .components()
234→                        .next()
235→                        .and_then(|c| c.as_os_str().to_str())
236→                        .map(String::from);
237→                    skills.push(meta);
238→                },
239→                Err(e) => {
240→                    tracing::warn!(
241→                        path = %sub_dir.path().display(),
242→                        %e,
243→                        "failed to parse embedded bundled SKILL.md"
244→                    );
245→                },
246→            }
247→        } else {
248→            // No SKILL.md here — recurse into subdirectories.
249→            discover_from_embedded_recursive(sub_dir, skills);
250→        }
251→    }
252→}
253→
254→/// Read SKILL.md body from the embedded directory.
255→fn read_skill_body_embedded(name: &str) -> Option<String> {
256→    let skill_dir = find_skill_dir_embedded(name)?;
257→    let skill_md = skill_dir.get_file("SKILL.md")?;
258→    let content = std::str::from_utf8(skill_md.contents()).ok()?;
259→    let synthetic_path =
260→        PathBuf::from("__bundled__").join(skill_dir.path().to_string_lossy().as_ref());
261→    let skill = parse::parse_skill(content, &synthetic_path).ok()?;
262→    Some(skill.body)
263→}
264→
265→fn read_sidecar_embedded(name: &str, rel_path: &str) -> Option<(Vec<u8>, bool)> {
266→    let skill_dir = find_skill_dir_embedded(name)?;
267→    let file = skill_dir.get_file(rel_path)?;
268→    let bytes = file.contents().to_vec();
269→    let is_utf8 = std::str::from_utf8(&bytes).is_ok();
270→    Some((bytes, is_utf8))
271→}
272→
273→fn list_sidecars_embedded(name: &str) -> Vec<(String, u64)> {
274→    let Some(skill_dir) = find_skill_dir_embedded(name) else {
275→        return Vec::new();
276→    };
277→    let mut out = Vec::new();
278→    for sub in crate::SIDECAR_SUBDIRS {
279→        let Some(sub_dir) = skill_dir.get_dir(sub) else {
280→            continue;
281→        };
282→        for file in sub_dir.files() {
283→            let file_name = file
284→                .path()
285→                .file_name()
286→                .and_then(|n| n.to_str())
287→                .unwrap_or("");
288→            out.push((format!("{sub}/{file_name}"), file.contents().len() as u64));
289→        }
290→    }
291→    out.sort_by(|a, b| a.0.cmp(&b.0));
292→    out
293→}
294→
295→/// Recursively find a skill subdirectory by name in the embedded tree.
296→fn find_skill_dir_embedded(name: &str) -> Option<&'static include_dir::Dir<'static>> {
297→    find_skill_dir_embedded_recursive(&BUNDLED_ASSETS, name)
298→}
299→
300→fn find_skill_dir_embedded_recursive(
301→    dir: &'static include_dir::Dir<'static>,
302→    name: &str,
303→) -> Option<&'static include_dir::Dir<'static>> {
304→    for sub_dir in dir.dirs() {
305→        let dir_name = sub_dir
306→            .path()
307→            .file_name()
308→            .and_then(|n| n.to_str())
309→            .unwrap_or("");
310→        if dir_name == name && sub_dir.get_file("SKILL.md").is_some() {
311→            return Some(sub_dir);
312→        }
313→        if let Some(found) = find_skill_dir_embedded_recursive(sub_dir, name) {
314→            return Some(found);
315→        }
316→    }
317→    None
318→}
319→
320→// ── Tests ───────────────────────────────────────────────────────────────────
321→
322→#[allow(clippy::unwrap_used, clippy::expect_used)]
323→#[cfg(test)]
324→mod tests {
325→    use super::*;
326→
327→    fn store() -> BundledSkillStore {
328→        BundledSkillStore::new()
329→    }
330→
331→    // ── Discovery ───────────────────────────────────────────────────────
332→
333→    #[test]
334→    fn bundled_skills_are_discovered() {
335→        let skills = store().discover();
336→        assert!(
337→            skills.len() >= 90,
338→            "expected ≥90 bundled skills, got {}",
339→            skills.len()
340→        );
341→        for skill in &skills {
342→            assert_eq!(skill.source, Some(SkillSource::Bundled));
343→            assert!(!skill.name.is_empty(), "skill has empty name");
344→            assert!(
345→                !skill.description.is_empty(),
346→                "skill {} has empty description",
347→                skill.name
348→            );
349→        }
350→    }
351→
352→    #[test]
353→    fn no_duplicate_skill_names() {
354→        let skills = store().discover();
355→        let mut seen = std::collections::HashSet::new();
356→        for skill in &skills {
357→            assert!(
358→                seen.insert(&skill.name),
359→                "duplicate bundled skill name: {}",
360→                skill.name
361→            );
362→        }
363→    }
364→
365→    #[test]
366→    fn all_names_pass_validation() {
367→        let skills = store().discover();
368→        for skill in &skills {
369→            assert!(
370→                parse::validate_name(&skill.name),
371→                "skill name '{}' fails validation",
372→                skill.name
373→            );
374→        }
375→    }
376→
377→    // ── Category ────────────────────────────────────────────────────────
378→
379→    #[test]
380→    fn every_bundled_skill_has_category() {
381→        let skills = store().discover();
382→        for skill in &skills {
383→            assert!(
384→                skill.category.is_some(),
385→                "skill '{}' has no category",
386→                skill.name
387→            );
388→            assert!(
389→                !skill.category.as_ref().is_none_or(String::is_empty),
390→                "skill '{}' has empty category",
391→                skill.name
392→            );
393→        }
394→    }
395→
396→    #[test]
397→    fn known_categories_present() {
398→        let skills = store().discover();
399→        let cats: std::collections::HashSet<String> =
400→            skills.iter().filter_map(|s| s.category.clone()).collect();
401→        // These categories must exist (from both hermes and openclaw copies).
402→        for expected in [
403→            "research",
404→            "creative",
405→            "mlops",
406→            "software-development",
407→            "productivity",
408→        ] {
409→            assert!(
410→                cats.contains(expected),
411→                "expected category '{}' not found in {:?}",
412→                expected,
413→                cats
414→            );
415→        }
416→    }
417→
418→    #[test]
419→    fn category_derived_from_top_level_directory() {
420→        let skills = store().discover();
421→        // axolotl lives at mlops/training/axolotl — category should be "mlops"
422→        let axolotl = skills.iter().find(|s| s.name == "axolotl");
423→        if let Some(skill) = axolotl {
424→            assert_eq!(skill.category.as_deref(), Some("mlops"));
425→        }
426→        // arxiv lives at research/arxiv — category should be "research"
427→        let arxiv = skills.iter().find(|s| s.name == "arxiv");
428→        if let Some(skill) = arxiv {
429→            assert_eq!(skill.category.as_deref(), Some("research"));
430→        }
431→    }
432→
433→    // ── Origin ──────────────────────────────────────────────────────────
434→
435→    #[test]
436→    fn all_bundled_skills_have_origin() {
437→        let skills = store().discover();
438→        for skill in &skills {
439→            assert!(
440→                skill.origin.is_some(),
441→                "skill '{}' has no origin metadata",
442→                skill.name
443→            );
444→        }
445→    }
446→
447→    #[test]
448→    fn origin_sources_are_known() {
449→        let skills = store().discover();
450→        let sources: std::collections::HashSet<String> = skills
451→            .iter()
452→            .filter_map(|s| s.origin.as_ref()?.source.clone())
453→            .collect();
454→        // All skills should come from one of our vetted sources.
455→        for source in &sources {
456→            assert!(
457→                source == "hermes-agent" || source == "openclaw",
458→                "unexpected origin source: '{}'",
459→                source
460→            );
461→        }
462→    }
463→
464→    // ── Content reading ─────────────────────────────────────────────────
465→
466→    #[test]
467→    fn every_bundled_skill_body_is_readable() {
468→        let s = store();
469→        let skills = s.discover();
470→        for skill in &skills {
471→            let body = s.read_skill(&skill.name);
472→            assert!(body.is_some(), "skill '{}' body not readable", skill.name);
473→            assert!(
474→                !body.as_ref().is_none_or(String::is_empty),
475→                "skill '{}' has empty body",
476→                skill.name
477→            );
478→        }
479→    }
480→
481→    #[test]
