 27→
 28→pub(crate) fn prompt_memory_snapshot_key(agent_id: &str) -> String {
 29→    format!("snapshot:{agent_id}")
 30→}
 31→
 32→pub(crate) async fn clear_prompt_memory_snapshot(
 33→    session_key: &str,
 34→    agent_id: &str,
 35→    state_store: Option<&SessionStateStore>,
 36→) -> bool {
 37→    let Some(store) = state_store else {
 38→        return false;
 39→    };
