 41→    match store
 42→        .delete(session_key, PROMPT_MEMORY_NAMESPACE, &key)
 43→        .await
 44→    {
 45→        Ok(deleted) => deleted,
 46→        Err(error) => {
 47→            warn!(
 48→                session = %session_key,
 49→                agent_id,
 50→                error = %error,
 51→                "failed to clear prompt memory snapshot"
 52→            );
 53→            false
 54→        },
 55→    }
