 58→pub(crate) fn prompt_memory_status(
 59→    style: MemoryStyle,
 60→    mode: PromptMemoryMode,
 61→    write_mode: AgentMemoryWriteMode,
 62→    snapshot_active: bool,
 63→    memory: Option<&LoadedWorkspaceMarkdown>,
 64→) -> PromptMemoryStatus {
 65→    PromptMemoryStatus {
 66→        style,
 67→        mode,
 68→        write_mode,
 69→        snapshot_active,
 70→        present: memory.is_some(),
 71→        chars: memory.map_or(0, |entry| entry.content.chars().count()),
 72→        path: memory.map(|entry| entry.path.to_string_lossy().into_owned()),
 73→        file_source: memory.map(|entry| entry.source),
 74→    }
