 77→pub(crate) fn resolve_prompt_agent_id(session_entry: Option<&SessionEntry>) -> String {
 78→    let Some(entry) = session_entry else {
 79→        return "main".to_string();
 80→    };
 81→    let Some(agent_id) = entry
 82→        .agent_id
 83→        .as_deref()
 84→        .map(str::trim)
 85→        .filter(|value| !value.is_empty())
 86→    else {
 87→        return "main".to_string();
 88→    };
 89→    if agent_id == "main" {
 90→        return "main".to_string();
 91→    }
 92→    if moltis_config::agent_workspace_dir(agent_id).exists() {
 93→        return agent_id.to_string();
 94→    }
 95→    warn!(
 96→        session = %entry.key,
 97→        agent_id,
 98→        "session references unknown agent workspace, falling back to main prompt persona"
 99→    );
100→    "main".to_string()
101→}
