103→/// Load identity, user profile, soul, and workspace text for one agent.
104→pub(crate) fn load_prompt_persona_base_for_agent(agent_id: &str) -> PromptPersona {
105→    let config = moltis_config::discover_and_load();
106→    let prompt_memory_mode = config.chat.prompt_memory_mode;
107→    let agent_write_mode = config.memory.agent_write_mode;
108→    let memory_style = config.memory.style;
109→    let mut identity = config.identity.clone();
110→    if let Some(file_identity) = moltis_config::load_identity_for_agent(agent_id) {
111→        if file_identity.name.is_some() {
112→            identity.name = file_identity.name;
113→        }
114→        if file_identity.emoji.is_some() {
115→            identity.emoji = file_identity.emoji;
116→        }
117→        if file_identity.theme.is_some() {
118→            identity.theme = file_identity.theme;
119→        }
120→    }
121→    let user = moltis_config::resolve_user_profile_from_config(&config);
122→    PromptPersona {
123→        config,
124→        identity,
125→        user,
126→        soul_text: moltis_config::load_soul_for_agent(agent_id),
127→        boot_text: moltis_config::load_boot_md_for_agent(agent_id),
128→        agents_text: moltis_config::load_agents_md_for_agent(agent_id),
129→        tools_text: moltis_config::load_tools_md_for_agent(agent_id),
130→        guidelines_text: moltis_config::load_guidelines_md_for_agent(agent_id),
131→        memory_text: None,
132→        memory_status: prompt_memory_status(
133→            memory_style,
134→            prompt_memory_mode,
135→            agent_write_mode,
136→            false,
137→            None,
138→        ),
139→    }
140→}
