142→pub(crate) fn load_prompt_persona_for_agent(agent_id: &str) -> PromptPersona {
143→    let mut persona = load_prompt_persona_base_for_agent(agent_id);
144→    let style = persona.config.memory.style;
145→    let mode = persona.config.chat.prompt_memory_mode;
146→    let write_mode = persona.config.memory.agent_write_mode;
147→    let memory = if memory_style_allows_prompt(style) {
148→        moltis_config::load_memory_md_for_agent_with_source(agent_id)
149→    } else {
150→        None
151→    };
152→    persona.memory_text = memory.as_ref().map(|entry| entry.content.clone());
153→    persona.memory_status = prompt_memory_status(style, mode, write_mode, false, memory.as_ref());
154→    persona
155→}
