157→pub(crate) async fn load_prompt_memory_for_session(
158→    session_key: &str,
159→    agent_id: &str,
160→    mode: PromptMemoryMode,
161→    state_store: Option<&SessionStateStore>,
162→) -> (Option<LoadedWorkspaceMarkdown>, bool) {
163→    let live_memory = || moltis_config::load_memory_md_for_agent_with_source(agent_id);
164→
165→    if !matches!(mode, PromptMemoryMode::FrozenAtSessionStart) {
166→        return (live_memory(), false);
167→    }
168→
169→    let Some(store) = state_store else {
170→        return (live_memory(), false);
171→    };
172→
173→    let key = prompt_memory_snapshot_key(agent_id);
174→    match store.get(session_key, PROMPT_MEMORY_NAMESPACE, &key).await {
175→        Ok(Some(raw)) => match serde_json::from_str::<Option<LoadedWorkspaceMarkdown>>(&raw) {
176→            Ok(snapshot) => return (snapshot, true),
177→            Err(error) => warn!(
178→                session = %session_key,
179→                agent_id,
180→                error = %error,
181→                "failed to deserialize prompt memory snapshot, rebuilding"
182→            ),
183→        },
184→        Ok(None) => {},
185→        Err(error) => warn!(
186→            session = %session_key,
187→            agent_id,
188→            error = %error,
189→            "failed to read prompt memory snapshot, falling back to live memory"
190→        ),
191→    }
192→
193→    let memory = live_memory();
194→    match serde_json::to_string(&memory) {
195→        Ok(serialized) => {
196→            if let Err(error) = store
197→                .set(session_key, PROMPT_MEMORY_NAMESPACE, &key, &serialized)
198→                .await
199→            {
200→                warn!(
201→                    session = %session_key,
202→                    agent_id,
203→                    error = %error,
204→                    "failed to persist prompt memory snapshot"
205→                );
206→                return (memory, false);
207→            }
208→            (memory, true)
209→        },
210→        Err(error) => {
211→            warn!(
212→                session = %session_key,
213→                agent_id,
214→                error = %error,
215→                "failed to serialize prompt memory snapshot"
216→            );
217→            (memory, false)
218→        },
219→    }
220→}
