222→pub(crate) async fn load_prompt_persona_for_session(
223→    session_key: &str,
224→    session_entry: Option<&SessionEntry>,
225→    state_store: Option<&SessionStateStore>,
226→) -> PromptPersona {
227→    let agent_id = resolve_prompt_agent_id(session_entry);
228→    let mut persona = load_prompt_persona_base_for_agent(&agent_id);
229→    let style = persona.config.memory.style;
230→    let mode = persona.config.chat.prompt_memory_mode;
231→    let write_mode = persona.config.memory.agent_write_mode;
232→    let (memory, snapshot_active) = if memory_style_allows_prompt(style) {
233→        load_prompt_memory_for_session(session_key, &agent_id, mode, state_store).await
234→    } else {
235→        (None, false)
236→    };
