351→pub(crate) async fn build_prompt_runtime_context(
352→    state: &Arc<dyn ChatRuntime>,
353→    provider: &Arc<dyn moltis_agents::model::LlmProvider>,
354→    session_key: &str,
355→    session_entry: Option<&SessionEntry>,
356→) -> PromptRuntimeContext {
357→    let data_dir = moltis_config::data_dir();
358→    let data_dir_display = data_dir.display().to_string();
359→
360→    let sudo_fut = detect_host_sudo_access();
361→    let sandbox_fut = async {
362→        if let Some(router) = state.sandbox_router() {
363→            let is_sandboxed = router.is_sandboxed(session_key).await;
364→            // Only include sandbox context when sandbox is actually enabled for
365→            // this session.  When disabled, omitting it prevents the LLM from
366→            // hallucinating sandbox usage (see #360).  This intentionally
367→            // discards `session_override` — its only consumer is the prompt
368→            // line we are omitting, and no other code reads it from
369→            // `PromptSandboxRuntimeContext`.
370→            if !is_sandboxed {
371→                return None;
372→            }
373→            let config = router.config();
374→            let backend_name = router.backend_name();
375→            let workspace_mount = config.workspace_mount.to_string();
376→            let workspace_path = (workspace_mount != "none").then(|| data_dir_display.clone());
377→            Some(PromptSandboxRuntimeContext {
378→                exec_sandboxed: true,
379→                mode: Some(config.mode.to_string()),
380→                backend: Some(backend_name.to_string()),
381→                scope: Some(config.scope.to_string()),
382→                image: Some(router.resolve_image(session_key, None).await),
383→                home: Some("/home/sandbox".to_string()),
384→                workspace_mount: Some(workspace_mount),
385→                workspace_path,
386→                no_network: prompt_sandbox_no_network_state(backend_name, config.no_network),
387→                session_override: session_entry.and_then(|entry| entry.sandbox_enabled),
388→            })
389→        } else {
390→            None
391→        }
392→    };
393→
394→    let ((sudo_non_interactive, sudo_status), sandbox_ctx) = tokio::join!(sudo_fut, sandbox_fut);
395→
396→    let configured_timezone = state
397→        .sandbox_router()
398→        .and_then(|r| r.config().timezone.clone());
399→    let timezone = Some(server_prompt_timezone(configured_timezone.as_deref()));
400→
401→    let location = state
402→        .cached_location()
403→        .await
404→        .as_ref()
405→        .map(|loc| loc.to_string());
406→    let channel_context = resolve_channel_runtime_context(session_key, session_entry);
407→
408→    let mut host_ctx = PromptHostRuntimeContext {
409→        host: Some(state.hostname().to_string()),
410→        os: Some(std::env::consts::OS.to_string()),
411→        arch: Some(std::env::consts::ARCH.to_string()),
412→        shell: detect_runtime_shell(),
413→        time: None,
414→        provider: Some(provider.name().to_string()),
415→        model: Some(provider.id().to_string()),
416→        session_key: Some(session_key.to_string()),
417→        surface: channel_context.surface,
418→        session_kind: channel_context.session_kind,
419→        channel_type: channel_context.channel_type,
420→        channel_account_id: channel_context.account_id,
421→        channel_chat_id: channel_context.chat_id,
422→        channel_chat_type: channel_context.chat_type,
423→        data_dir: Some(data_dir_display),
424→        sudo_non_interactive,
425→        sudo_status,
426→        timezone,
427→        location,
428→        ..Default::default()
429→    };
430→    refresh_runtime_prompt_time(&mut host_ctx);
431→
432→    // Build nodes context from connected remote nodes.
433→    let connected = state.connected_nodes().await;
434→    let nodes_ctx = if connected.is_empty() {
435→        None
436→    } else {
437→        let default_node_id = session_entry.and_then(|e| e.node_id.clone());
438→        Some(PromptNodesRuntimeContext {
439→            nodes: connected
440→                .into_iter()
441→                .map(|n| PromptNodeInfo {
442→                    node_id: n.node_id,
443→                    display_name: n.display_name,
444→                    platform: n.platform,
445→                    capabilities: n.capabilities,
446→                    cpu_count: n.cpu_count,
447→                    mem_total: n.mem_total,
448→                    runtimes: n.runtimes,
449→                    providers: n.providers,
450→                })
451→                .collect(),
452→            default_node_id,
453→        })
454→    };
455→
456→    PromptRuntimeContext {
457→        host: host_ctx,
458→        sandbox: sandbox_ctx,
459→        nodes: nodes_ctx,
460→    }
461→}
