463→pub(crate) fn apply_request_runtime_context(host: &mut PromptHostRuntimeContext, params: &Value) {
464→    host.accept_language = params
465→        .get("_accept_language")
466→        .and_then(|v| v.as_str())
467→        .map(String::from);
468→    host.remote_ip = params
469→        .get("_remote_ip")
470→        .and_then(|v| v.as_str())
471→        .map(String::from);
472→
473→    // Extract sender_id from channel metadata (set by channel handlers).
474→    if host.channel_sender_id.is_none() {
475→        host.channel_sender_id = params
476→            .get("channel")
477→            .and_then(|ch| ch.get("sender_id"))
478→            .and_then(|v| v.as_str())
479→            .map(String::from);
480→    }
481→
482→    if let Some(timezone) =
483→        normalized_iana_timezone(params.get("_timezone").and_then(|v| v.as_str()))
484→            .or_else(default_user_prompt_timezone)
485→    {
486→        host.timezone = Some(timezone);
487→    }
488→
489→    refresh_runtime_prompt_time(host);
490→}
