492→pub(crate) fn apply_runtime_tool_filters(
493→    base: &moltis_agents::tool_registry::ToolRegistry,
494→    config: &moltis_config::MoltisConfig,
495→    _skills: &[moltis_skills::types::SkillMetadata],
496→    mcp_disabled: bool,
497→    policy_context: &PolicyContext,
498→) -> moltis_agents::tool_registry::ToolRegistry {
499→    let base_registry = if mcp_disabled {
500→        base.clone_without_mcp()
501→    } else {
502→        base.clone_without(&[])
503→    };
504→
505→    let policy = resolve_effective_policy(config, policy_context);
506→    // NOTE: Do not globally restrict tools by discovered skill `allowed_tools`.
507→    // Skills are always discovered for prompt injection; applying those lists at
508→    // runtime can unintentionally remove unrelated tools (for example, leaving
509→    // only `web_fetch` and preventing `create_skill` from being called).
510→    // Tool availability here is controlled by configured runtime policy.
511→    base_registry.clone_allowed_by(|name| policy.is_allowed(name))
512→}
