514→/// Build a `PolicyContext` from runtime context and request parameters.
515→pub(crate) fn build_policy_context(
516→    agent_id: &str,
517→    runtime_context: Option<&PromptRuntimeContext>,
518→    params: Option<&Value>,
519→) -> PolicyContext {
520→    let host = runtime_context.map(|rc| &rc.host);
521→    // sender_id: prefer params["channel"]["sender_id"] (fresh from channel
522→    // dispatch), fall back to host.channel_sender_id (set by
523→    // apply_request_runtime_context earlier in the call chain).
524→    let sender_id = params
525→        .and_then(|p| p.get("channel"))
526→        .and_then(|ch| ch.get("sender_id"))
527→        .and_then(|v| v.as_str())
528→        .map(String::from)
529→        .or_else(|| host.and_then(|h| h.channel_sender_id.clone()));
530→    PolicyContext {
531→        agent_id: agent_id.to_string(),
532→        provider: host.and_then(|h| h.provider.clone()),
533→        channel: host.and_then(|h| h.channel_type.clone()),
534→        channel_account_id: host.and_then(|h| h.channel_account_id.clone()),
535→        group_id: host.and_then(|h| h.channel_chat_type.clone()),
536→        sender_id,
537→        sandboxed: runtime_context
538→            .and_then(|rc| rc.sandbox.as_ref())
539→            .is_some_and(|s| s.exec_sandboxed),
540→    }
541→}
