 27→pub(crate) async fn mark_unsupported_model(
 28→    state: &Arc<dyn ChatRuntime>,
 29→    model_store: &Arc<RwLock<DisabledModelsStore>>,
 30→    model_id: &str,
 31→    provider_name: &str,
 32→    error_obj: &Value,
 33→) {
 34→    if error_obj.get("type").and_then(|v| v.as_str()) != Some("unsupported_model") {
 35→        return;
 36→    }
 37→
 38→    let detail = error_obj
 39→        .get("detail")
 40→        .and_then(|v| v.as_str())
 41→        .unwrap_or("Model is not supported for this account/provider");
 42→    let provider = error_obj
 43→        .get("provider")
 44→        .and_then(|v| v.as_str())
 45→        .unwrap_or(provider_name);
 46→
 47→    let mut store = model_store.write().await;
 48→    if store.mark_unsupported(model_id, detail, Some(provider)) {
 49→        let unsupported = store.unsupported_info(model_id).cloned();
 50→        if let Err(err) = store.save() {
 51→            warn!(
 52→                model = model_id,
 53→                provider = provider,
 54→                error = %err,
 55→                "failed to persist unsupported model flag"
 56→            );
 57→        } else {
 58→            info!(
 59→                model = model_id,
 60→                provider = provider,
 61→                "flagged model as unsupported"
 62→            );
 63→        }
 64→        drop(store);
 65→        broadcast(
 66→            state,
 67→            "models.updated",
 68→            serde_json::json!({
 69→                "modelId": model_id,
 70→                "unsupported": true,
 71→                "unsupportedReason": unsupported.as_ref().map(|u| u.detail.as_str()).unwrap_or(detail),
 72→                "unsupportedProvider": unsupported
 73→                    .as_ref()
 74→                    .and_then(|u| u.provider.as_deref())
 75→                    .unwrap_or(provider),
 76→                "unsupportedUpdatedAt": unsupported.map(|u| u.updated_at_ms).unwrap_or_else(now_ms),
 77→            }),
 78→            BroadcastOpts::default(),
 79→        )
 80→        .await;
 81→    }
 82→}
