114→pub(crate) fn ordered_runner_event_callback() -> (
115→    Box<dyn Fn(RunnerEvent) + Send + Sync>,
116→    mpsc::UnboundedReceiver<RunnerEvent>,
117→) {
118→    let (tx, rx) = mpsc::unbounded_channel::<RunnerEvent>();
119→    let callback: Box<dyn Fn(RunnerEvent) + Send + Sync> = Box::new(move |event| {
120→        if tx.send(event).is_err() {
121→            debug!("runner event dropped because event processor is closed");
122→        }
123→    });
124→    (callback, rx)
125→}
