 62→    async fn send_sync(&self, params: Value) -> ServiceResult {
 63→        let text = params
 64→            .get("text")
 65→            .and_then(|v| v.as_str())
 66→            .ok_or_else(|| "missing 'text' parameter".to_string())?
 67→            .to_string();
 68→        let desired_reply_medium = infer_reply_medium(&params, &text);
 69→        let requested_agent_id = params
 70→            .get("agent_id")
 71→            .and_then(|v| v.as_str())
 72→            .map(str::trim)
 73→            .filter(|value| !value.is_empty())
 74→            .map(str::to_string);
 75→        let request_tool_policy = params
 76→            .get("_tool_policy")
 77→            .cloned()
 78→            .map(serde_json::from_value::<ToolPolicy>)
 79→            .transpose()
 80→            .map_err(|e| format!("invalid '_tool_policy' parameter: {e}"))?;
 81→
 82→        let explicit_model = params.get("model").and_then(|v| v.as_str());
 83→        let stream_only = !self.has_tools_sync();
 84→
 85→        // Resolve session key from explicit override.
 86→        let session_key = match params.get("_session_key").and_then(|v| v.as_str()) {
 87→            Some(sk) => sk.to_string(),
 88→            None => "main".to_string(),
 89→        };
 90→
 91→        // Resolve provider.
 92→        let provider: Arc<dyn moltis_agents::model::LlmProvider> = {
 93→            let reg = self.providers.read().await;
 94→            if let Some(id) = explicit_model {
 95→                reg.get(id)
 96→                    .ok_or_else(|| format!("model '{id}' not found"))?
 97→            } else if !stream_only {
 98→                reg.first_with_tools()
 99→                    .ok_or_else(|| "no LLM providers configured".to_string())?
100→            } else {
101→                reg.first()
102→                    .ok_or_else(|| "no LLM providers configured".to_string())?
103→            }
104→        };
105→
106→        let user_audio = user_audio_path_from_params(&params, &session_key);
107→        let user_documents =
108→            user_documents_from_params(&params, &session_key, self.session_store.as_ref());
109→        // Persist the user message.
