 93→
 94→/// Discoverer that merges filesystem-discovered skills with bundled skills.
 95→///
 96→/// Bundled skills are appended at lowest priority: any user skill with the
 97→/// same name takes precedence. This ensures users can override or shadow a
 98→/// bundled skill by creating one with the same name in their personal or
 99→/// project skills directory.
100→#[cfg(feature = "bundled-skills")]
101→pub struct CompositeSkillDiscoverer {
102→    inner: Box<dyn SkillDiscoverer>,
103→    bundled: Arc<crate::bundled::BundledSkillStore>,
104→}
105→
106→#[cfg(feature = "bundled-skills")]
107→impl CompositeSkillDiscoverer {
108→    pub fn new(
109→        inner: Box<dyn SkillDiscoverer>,
110→        bundled: Arc<crate::bundled::BundledSkillStore>,
111→    ) -> Self {
112→        Self { inner, bundled }
113→    }
114→}
115→
116→#[cfg(feature = "bundled-skills")]
117→#[async_trait]
118→impl SkillDiscoverer for CompositeSkillDiscoverer {
119→    async fn discover(&self) -> Result<Vec<SkillMetadata>> {
120→        let mut skills = self.inner.discover().await?;
121→        let mut seen: std::collections::HashSet<String> =
122→            skills.iter().map(|s| s.name.clone()).collect();
123→        for bundled in self.bundled.discover() {
124→            if seen.insert(bundled.name.clone()) {
125→                skills.push(bundled);
126→            }
127→        }
128→        Ok(skills)
129→    }
130→}
