132→// ── Filesystem scanning helpers ─────────────────────────────────────────────
133→
134→/// Scan one level deep for SKILL.md dirs (project/personal sources).
135→fn discover_flat(base_path: &Path, source: &SkillSource, skills: &mut Vec<SkillMetadata>) {
136→    let entries = match std::fs::read_dir(base_path) {
137→        Ok(e) => e,
138→        Err(_) => return,
139→    };
140→
141→    for entry in entries.flatten() {
142→        let skill_dir = entry.path();
143→        if !skill_dir.is_dir() {
144→            continue;
145→        }
146→        let skill_md = skill_dir.join("SKILL.md");
147→        if !skill_md.is_file() {
148→            continue;
149→        }
150→        let content = match std::fs::read_to_string(&skill_md) {
151→            Ok(c) => c,
152→            Err(e) => {
153→                tracing::warn!(?skill_md, %e, "failed to read SKILL.md");
154→                continue;
155→            },
156→        };
157→        match parse::parse_metadata(&content, &skill_dir) {
158→            Ok(mut meta) => {
159→                meta.source = Some(source.clone());
160→                tracing::debug!(
161→                    path = %skill_md.display(),
162→                    source = ?source,
163→                    name = %meta.name,
164→                    "loaded SKILL.md"
165→                );
166→                skills.push(meta);
167→            },
168→            Err(e) => {
169→                tracing::warn!(?skill_dir, %e, "failed to parse SKILL.md");
170→            },
171→        }
172→    }
173→}
