175→/// Discover enabled plugin skills using the plugins manifest.
176→/// Plugin skills don't have SKILL.md — they are normalized by format adapters.
177→/// This returns lightweight metadata from the manifest for prompt injection.
178→fn discover_plugins(install_dir: &Path, skills: &mut Vec<SkillMetadata>) {
179→    let manifest_path = moltis_config::data_dir().join("plugins-manifest.json");
180→    let store = ManifestStore::new(manifest_path);
181→    let manifest = match store.load() {
182→        Ok(m) => m,
183→        Err(e) => {
184→            tracing::warn!(%e, "failed to load plugins manifest");
185→            return;
186→        },
187→    };
188→
189→    for repo in &manifest.repos {
190→        for skill_state in &repo.skills {
191→            if !skill_state.enabled || !skill_state.trusted {
192→                continue;
193→            }
194→            let skill_dir = install_dir.join(&skill_state.relative_path);
195→            skills.push(SkillMetadata {
196→                name: skill_state.name.clone(),
197→                path: skill_dir,
198→                source: Some(SkillSource::Plugin),
199→                ..Default::default()
200→            });
201→        }
202→    }
203→}
204→
205→/// Discover registry skills using the manifest for enabled filtering.
206→///
207→/// Handles both formats:
208→/// - `PluginFormat::Skill` → parse `SKILL.md` from disk for full metadata
209→/// - Other formats → create stub metadata with `SkillSource::Plugin` (prompt_gen
210→///   uses the path as-is instead of appending `/SKILL.md`)
211→fn discover_registry(install_dir: &Path, skills: &mut Vec<SkillMetadata>) {
212→    let manifest_path = match ManifestStore::default_path() {
213→        Ok(p) => p,
214→        Err(_) => return,
215→    };
216→    let store = ManifestStore::new(manifest_path);
217→    let manifest = match store.load() {
218→        Ok(m) => m,
219→        Err(e) => {
220→            tracing::warn!(%e, "failed to load skills manifest");
221→            return;
222→        },
223→    };
224→
225→    for repo in &manifest.repos {
226→        for skill_state in &repo.skills {
227→            if !skill_state.enabled || !skill_state.trusted {
228→                continue;
229→            }
230→            let skill_dir = install_dir.join(&skill_state.relative_path);
231→
232→            match repo.format {
233→                PluginFormat::Skill => {
234→                    let skill_md = skill_dir.join("SKILL.md");
235→                    if !skill_md.is_file() {
236→                        tracing::warn!(?skill_md, "manifest references missing SKILL.md");
237→                        continue;
238→                    }
239→                    let content = match std::fs::read_to_string(&skill_md) {
240→                        Ok(c) => c,
241→                        Err(e) => {
242→                            tracing::warn!(?skill_md, %e, "failed to read SKILL.md");
243→                            continue;
244→                        },
245→                    };
246→                    match parse::parse_metadata(&content, &skill_dir) {
247→                        Ok(mut meta) => {
248→                            meta.source = Some(SkillSource::Registry);
249→                            tracing::debug!(
250→                                path = %skill_md.display(),
251→                                source = "registry",
252→                                name = %meta.name,
253→                                "loaded SKILL.md"
254→                            );
255→                            skills.push(meta);
256→                        },
257→                        Err(e) => {
258→                            tracing::debug!(?skill_dir, %e, "skipping non-conforming SKILL.md");
259→                        },
260→                    }
261→                },
262→                _ => {
263→                    // Non-SKILL.md formats: stub metadata with Plugin source
264→                    // so prompt_gen uses the path directly (no /SKILL.md append).
265→                    skills.push(SkillMetadata {
266→                        name: skill_state.name.clone(),
267→                        path: skill_dir,
268→                        source: Some(SkillSource::Plugin),
269→                        ..Default::default()
270→                    });
271→                },
272→            }
273→        }
274→    }
275→}
