  6→/// Name of the native read tool advertised in the activation instruction.
  7→/// Kept as a constant so the gateway can assert a parity invariant between
  8→/// this string and the registered tool's [`AgentTool::name`] at test time.
  9→pub const READ_SKILL_TOOL_NAME: &str = "read_skill";
 10→
 11→/// Default character budget for the skills prompt block. At ~4 chars/token
 12→/// this is ~7,500 tokens — generous for 100+ skills in full format.
 13→const DEFAULT_MAX_CHARS: usize = 30_000;
 14→
 15→/// Generate the `<available_skills>` XML block for injection into the system prompt.
 16→///
 17→/// Uses a two-tier format strategy with a character budget (default 30 KB):
 18→///
 19→/// 1. **Full format** — each skill gets `name`, `source`, `category`, and
 20→///    description. Used when all skills fit within the budget.
 21→/// 2. **Compact format** — drops descriptions, keeps only `name`, `source`,
 22→///    and `category`. Triggered when full format exceeds the budget. Preserves
 23→///    awareness of all skills before dropping any.
 24→///
 25→/// If even compact format exceeds the budget, skills are truncated (lowest
 26→/// priority last — bundled skills are appended after user skills).
 27→pub fn generate_skills_prompt(skills: &[SkillMetadata]) -> String {
 28→    generate_skills_prompt_with_budget(skills, DEFAULT_MAX_CHARS)
 29→}
 30→
 31→/// Generate the skills prompt with an explicit character budget.
 32→pub fn generate_skills_prompt_with_budget(skills: &[SkillMetadata], max_chars: usize) -> String {
 33→    if skills.is_empty() {
 34→        return String::new();
 35→    }
 36→
 37→    let activation = build_activation_instruction();
 38→
 39→    // Try full format first.
 40→    let full = build_skills_block(skills, Format::Full);
 41→    if full.len() + activation.len() <= max_chars {
 42→        return format!("## Available Skills\n\n{full}\n{activation}");
 43→    }
 44→
 45→    // Fall back to compact format (drop descriptions).
 46→    let compact = build_skills_block(skills, Format::Compact);
 47→    if compact.len() + activation.len() <= max_chars {
 48→        return format!(
 49→            "## Available Skills (compact — call `{READ_SKILL_TOOL_NAME}` to see full descriptions)\n\n\
 50→             {compact}\n{activation}"
 51→        );
 52→    }
 53→
 54→    // Compact still too large — binary search for the largest prefix that fits.
 55→    let mut lo = 0usize;
 56→    let mut hi = skills.len();
 57→    while lo < hi {
 58→        let mid = (lo + hi).div_ceil(2);
 59→        let block = build_skills_block(&skills[..mid], Format::Compact);
 60→        if block.len() + activation.len() <= max_chars {
 61→            lo = mid;
 62→        } else {
 63→            hi = mid - 1;
 64→        }
 65→    }
 66→    let truncated = build_skills_block(&skills[..lo], Format::Compact);
 67→    format!(
 68→        "## Available Skills (compact, showing {lo} of {} — call `{READ_SKILL_TOOL_NAME}` to browse all)\n\n\
 69→         {truncated}\n{activation}",
 70→        skills.len()
 71→    )
 72→}
 73→
 74→#[derive(Clone, Copy, PartialEq, Eq)]
 75→enum Format {
 76→    Full,
 77→    Compact,
 78→}
 79→
 80→fn build_skills_block(skills: &[SkillMetadata], format: Format) -> String {
 81→    let mut out = String::from("<available_skills>\n");
 82→    for skill in skills {
 83→        let source = match skill.source.as_ref() {
 84→            Some(SkillSource::Plugin) => "plugin",
 85→            Some(SkillSource::Bundled) => "bundled",
 86→            _ => "skill",
 87→        };
 88→        let category_attr = skill
 89→            .category
 90→            .as_deref()
 91→            .map(|c| format!(" category=\"{c}\""))
 92→            .unwrap_or_default();
 93→        match format {
 94→            Format::Full => {
 95→                out.push_str(&format!(
 96→                    "<skill name=\"{}\" source=\"{}\"{category_attr}>\n{}\n</skill>\n",
 97→                    skill.name, source, skill.description,
 98→                ));
