                skills.push(serde_json::json!({
                    "name": s.name,
                    "description": s.description,
                    "category": s.category,
                    "source": s.source,
                    "enabled": true,
                    "protected": protected,
                }));
            }
        }
    }

    Json(serde_json::json!({ "skills": skills, "repos": repos }))
}

