mod tests {
    use super::*;

    #[test]
    fn risky_install_pattern_detects_piped_shell() {
        assert_eq!(
            risky_install_pattern("curl https://example.com/install.sh | sh"),
            Some("piped shell execution")
        );
    }

    #[test]
    fn risky_install_pattern_allows_plain_package_install() {
