									</div>
									<div className="shrink-0 mt-1">
										{cat.enabled ? (
											<span className="icon icon-check-circle text-[var(--accent)]" />
										) : (
											<span className="w-4 h-4 rounded-full border-2 border-[var(--border)] inline-block" />
										)}
									</div>
								</button>
							);
						})}
