 155→function doInstall(source: string): Promise<void> {
 156→	if (!(source && S.connected)) {
 157→		if (!S.connected) showToast("Not connected to gateway.", "error");
 158→		return Promise.resolve();
 159→	}
 160→	const opId = `skills-install-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
 161→	const pid = startInstallProgress(source, opId);
 162→	return sendRpc("skills.install", { source, op_id: opId }).then((res) => {
 163→		if (res?.ok) {
 164→			const p = (res.payload || {}) as Record<string, unknown[]>;
 165→			showToast(`Installed ${source} (${(p.installed || []).length} skills)`, "success");
 166→			fetchAll();
 167→			stopInstallProgress(pid, true);
 168→		} else {
 169→			showToast(`Failed: ${res?.error || "unknown error"}`, "error");
 170→			stopInstallProgress(pid, false);
 171→		}
 172→	});
 173→}
 174→function doImportBundle(path: string): Promise<void> {
 175→	if (!(path && S.connected)) {
 176→		if (!S.connected) showToast("Not connected.", "error");
 177→		return Promise.resolve();
 178→	}
 179→	return sendRpc("skills.repos.import", { path }).then((res) => {
 180→		if (res?.ok) {
 181→			const p = (res.payload || {}) as Record<string, unknown>;
 182→			showToast(`Imported ${p.repo_name || "bundle"} (${p.skill_count || 0} skills)`, "success");
 183→			fetchAll();
 184→		} else showToast(`Failed: ${res?.error || "unknown"}`, "error");
 185→	});
 186→}
 187→function doExportBundle(source: string, path: string | null): Promise<void> {
 188→	if (!(source && S.connected)) return Promise.resolve();
 189→	const params: Record<string, string> = { source };
 190→	if (path) params.path = path;
 191→	return sendRpc("skills.repos.export", params).then((res) => {
 192→		if (res?.ok) showToast(`Exported ${source}`, "success");
 193→		else showToast(`Failed: ${res?.error || "unknown"}`, "error");
 194→	});
 195→}
