 971→function EnabledSkillsTable(): VNode | null {
 972→	const s = enabledSkills.value;
 973→	const map = skillRepoMap.value;
 974→	const activeDetail = useSignal<SkillDetail | null>(null);
 975→	const detailLoading = useSignal(false);
 976→	const pending = useSignal<string | null>(null);
 977→	const activeCategory = useSignal<string | null>(null);
 978→	const searchQuery = useSignal("");
 979→	if (!s?.length) return null;
 980→
 981→	// Build sorted category list from skills
 982→	const categories = computed(() => {
 983→		const cats = new Set<string>();
 984→		for (const sk of enabledSkills.value) {
 985→			cats.add(sk.category || "other");
 986→		}
 987→		return Array.from(cats).sort();
 988→	});
 989→
 990→	// Filter skills by search query and active category
 991→	const filtered = s.filter((sk) => {
 992→		if (activeCategory.value && (sk.category || "other") !== activeCategory.value) return false;
 993→		if (searchQuery.value) {
 994→			const q = searchQuery.value.toLowerCase();
 995→			return sk.name.toLowerCase().includes(q) || (sk.description || "").toLowerCase().includes(q);
 996→		}
 997→		return true;
 998→	});
 999→
1000→	function isDisc(sk: SkillSummary): boolean {
1001→		return isDiscoveredSource(sk.source);
1002→	}
1003→	function doDisable(sk: SkillSummary): void {
1004→		pending.value = sk.name;
1005→		sendRpc("skills.skill.disable", { source: map[sk.name] || sk.source, skill: sk.name }).then((r) => {
1006→			pending.value = null;
1007→			if (r?.ok) {
1008→				activeDetail.value = null;
1009→				showToast(isDisc(sk) ? `Deleted ${sk.name}` : `Disabled ${sk.name}`, "success");
1010→				fetchAll();
1011→			} else showToast(`Failed: ${r?.error || "unknown"}`, "error");
1012→		});
1013→	}
1014→	function onDisable(sk: SkillSummary): void {
1015→		if (pending.value) return;
1016→		if (isDisc(sk) && sk.protected) {
1017→			showToast("Protected", "error");
1018→			return;
1019→		}
1020→		if (isDisc(sk)) {
1021→			requestConfirm(`Delete "${sk.name}"?`, { confirmLabel: "Delete", danger: true }).then((y) => {
1022→				if (y) doDisable(sk);
1023→			});
1024→			return;
1025→		}
1026→		doDisable(sk);
1027→	}
1028→	function loadDetail(sk: SkillSummary): void {
1029→		if (activeDetail.value?.name === sk.name) {
1030→			activeDetail.value = null;
1031→			return;
1032→		}
1033→		detailLoading.value = true;
1034→		sendRpc("skills.skill.detail", { source: map[sk.name] || sk.source, skill: sk.name }).then((r) => {
1035→			detailLoading.value = false;
1036→			if (r?.ok) activeDetail.value = r.payload as SkillDetail;
1037→		});
1038→	}
1039→	return (
1040→		<div className="skills-section">
1041→			<div className="flex items-center gap-3 mb-2">
1042→				<h3 className="skills-section-title" style={{ margin: 0 }}>
1043→					Enabled Skills
1044→					<span className="ml-2 text-xs font-normal text-[var(--muted)]">
1045→						({filtered.length}
1046→						{filtered.length !== s.length ? ` of ${s.length}` : ""})
1047→					</span>
1048→				</h3>
1049→				<input
1050→					type="text"
1051→					placeholder="Search skills..."
1052→					value={searchQuery.value}
1053→					onInput={(e) => {
1054→						searchQuery.value = (e.target as HTMLInputElement).value;
1055→					}}
1056→					className="skills-install-input"
1057→					style={{ maxWidth: "240px", fontSize: ".78rem", padding: "4px 8px" }}
1058→				/>
1059→			</div>
1060→			{categories.value.length > 1 && (
1061→				<div className="flex flex-wrap gap-1.5 mb-3">
1062→					<button
1063→						className={`skills-category-pill ${activeCategory.value === null ? "active" : ""}`}
1064→						onClick={() => {
1065→							activeCategory.value = null;
1066→						}}
1067→					>
1068→						All ({s.length})
1069→					</button>
1070→					{categories.value.map((cat) => {
1071→						const count = s.filter((sk) => (sk.category || "other") === cat).length;
1072→						return (
1073→							<button
1074→								key={cat}
1075→								className={`skills-category-pill ${activeCategory.value === cat ? "active" : ""}`}
1076→								onClick={() => {
1077→									activeCategory.value = activeCategory.value === cat ? null : cat;
1078→								}}
1079→							>
1080→								{cat} ({count})
1081→							</button>
1082→						);
1083→					})}
1084→				</div>
1085→			)}
1086→			<div className="skills-table-wrap">
1087→				<table style={{ width: "100%", borderCollapse: "collapse", fontSize: ".82rem" }}>
1088→					<thead>
1089→						<tr style={{ borderBottom: "1px solid var(--border)", background: "var(--surface)" }}>
1090→							<th
1091→								style={{
1092→									textAlign: "left",
1093→									padding: "8px 12px",
1094→									fontWeight: 500,
1095→									color: "var(--muted)",
1096→									fontSize: ".75rem",
1097→									textTransform: "uppercase",
1098→								}}
1099→							>
1100→								Name
1101→							</th>
1102→							<th
1103→								style={{
1104→									textAlign: "left",
1105→									padding: "8px 12px",
1106→									fontWeight: 500,
1107→									color: "var(--muted)",
1108→									fontSize: ".75rem",
1109→									textTransform: "uppercase",
1110→								}}
1111→							>
1112→								Description
1113→							</th>
1114→							<th
1115→								style={{
1116→									textAlign: "left",
1117→									padding: "8px 12px",
1118→									fontWeight: 500,
1119→									color: "var(--muted)",
1120→									fontSize: ".75rem",
1121→									textTransform: "uppercase",
1122→								}}
1123→							>
1124→								Source
1125→							</th>
1126→							<th />
1127→						</tr>
1128→					</thead>
1129→					<tbody>
1130→						{filtered.map((sk) => {
1131→							const isActive = activeDetail.value?.name === sk.name;
1132→							return (
1133→								<>
1134→									<tr
1135→										key={sk.name}
1136→										className="cursor-pointer"
1137→										style={{
1138→											borderBottom: isActive ? "none" : "1px solid var(--border)",
1139→											background: isActive ? "var(--bg-hover)" : undefined,
1140→										}}
1141→										onClick={() => loadDetail(sk)}
1142→									>
1143→										<td
1144→											style={{
1145→												padding: "8px 12px",
1146→												fontWeight: 500,
1147→												color: "var(--accent)",
1148→												fontFamily: "var(--font-mono)",
1149→											}}
1150→										>
1151→											{sk.name}
1152→											{sk.category && !activeCategory.value && (
1153→												<span className="skills-category-badge">{sk.category}</span>
