1158→											<span className={isRepoSource(sk.source) ? "tier-badge" : "recommended-badge"}>{sk.source}</span>
1159→										</td>
1160→										<td style={{ padding: "8px 12px", textAlign: "right" }}>
1161→											{sk.source !== SkillSource.Bundled && (
1162→												<button
1163→													disabled={(isDisc(sk) && sk.protected === true) || pending.value === sk.name}
1164→													className={
1165→														isDisc(sk)
1166→															? "provider-btn provider-btn-sm provider-btn-danger"
1167→															: "provider-btn provider-btn-sm provider-btn-secondary"
1168→													}
1169→													onClick={(e) => {
1170→														e.stopPropagation();
1171→														onDisable(sk);
1172→													}}
1173→												>
1174→													{pending.value === sk.name ? "..." : isDisc(sk) ? "Delete" : "Disable"}
1175→												</button>
1176→											)}
1177→										</td>
1178→									</tr>
1179→									{isActive && activeDetail.value && (
1180→										<tr key={`${sk.name}-detail`}>
1181→											<td colSpan={4} style={{ padding: 0, borderBottom: "1px solid var(--border)" }}>
1182→												<SkillDetailPanel
1183→													detail={activeDetail.value}
1184→													repoSource={activeDetail.value.source}
1185→													onClose={() => {
1186→														activeDetail.value = null;
1187→													}}
1188→													onReload={() =>
1189→														loadDetail({
1190→															name: activeDetail.value?.name,
1191→															source: activeDetail.value?.source,
1192→														} as SkillSummary)
1193→													}
1194→												/>
1195→											</td>
1196→										</tr>
1197→									)}
1198→								</>
1199→							);
1200→						})}
1201→					</tbody>
1202→				</table>
1203→			</div>
1204→		</div>
1205→	);
1206→}
1207→
1208→function SkillsPageComponent(): VNode {
1209→	useEffect(() => {
1210→		ensurePrefetch().then(() => fetchAll());
1211→		const off = onEvent("skills.install.progress", (p: unknown) => {
1212→			const d = p as Record<string, string>;
1213→			if (!d?.op_id) return;
1214→			if (d.phase === "start") startInstallProgress(d.source || "repository", d.op_id);
1215→			else if (d.phase === "done") stopInstallProgress(d.op_id, true);
1216→			else if (d.phase === "error") stopInstallProgress(d.op_id, false);
1217→		});
1218→		return off;
1219→	}, []);
1220→	return (
1221→		<div className="flex-1 flex flex-col min-w-0 p-4 gap-4 overflow-y-auto">
1222→			<div className="flex items-center gap-3">
1223→				<h2 className="text-lg font-medium text-[var(--text-strong)]">Skills</h2>
1224→				<button className="provider-btn provider-btn-secondary provider-btn-sm" onClick={fetchAll}>
1225→					Refresh
1226→				</button>
1227→				<button className="provider-btn provider-btn-danger provider-btn-sm" onClick={emergencyDisableAllSkills}>
1228→					Emergency Disable
1229→				</button>
1230→			</div>
1231→			<p className="text-sm text-[var(--muted)]">
1232→				SKILL.md-based skills.{" "}
1233→				<a
1234→					href="https://platform.claude.com/docs/en/agents-and-tools/agent-skills/overview"
1235→					target="_blank"
1236→					rel="noopener noreferrer"
1237→					className="text-[var(--accent)]"
1238→				>
1239→					How to write a skill?
