1248→			<ReposSection />
1249→			{loading.value && !enabledSkills.value.length && !repos.value.length && (
1250→				<div style={{ padding: "24px", textAlign: "center", color: "var(--muted)" }}>Loading skills...</div>
1251→			)}
1252→			<EnabledSkillsTable />
1253→		</div>
