 64→export function RemoteAccessSection(): VNode {
 65→	const [tsStatus, setTsStatus] = useState<TailscaleStatus | null>(null);
 66→	const [tsError, setTsError] = useState<string | null>(null);
 67→	const [tsWarning, setTsWarning] = useState<string | null>(null);
 68→	const [tsLoading, setTsLoading] = useState(true);
