 70→	const [configuringMode, setConfiguringMode] = useState<string | null>(null);
 71→	const [ngStatus, setNgStatus] = useState<NgrokStatus | null>(null);
 72→	const [ngError, setNgError] = useState<string | null>(null);
 73→	const [ngLoading, setNgLoading] = useState(true);
 74→	const [ngSaving, setNgSaving] = useState(false);
 75→	const [ngMsg, setNgMsg] = useState<string | null>(null);
 76→	const [ngForm, setNgForm] = useState<NgrokForm>({
 77→		enabled: false,
 78→		authtoken: "",
 79→		clearAuthtoken: false,
 80→		domain: "",
 81→	});
 82→	const [authReady, setAuthReady] = useState(false);
 83→
 84→	function fetchTsStatus(): void {
 85→		setTsLoading(true);
 86→		rerender();
 87→		fetch("/api/tailscale/status")
 88→			.then((r) => {
 89→				const ct = r.headers.get("content-type") || "";
 90→				if (r.status === 404 || !ct.includes("application/json")) {
 91→					setTsError("Tailscale feature is not enabled. Rebuild with --features tailscale.");
 92→					setTsLoading(false);
 93→					rerender();
 94→					return null;
 95→				}
 96→				return r.json();
 97→			})
 98→			.then((data: TailscaleStatus | null) => {
 99→				if (!data) return;
100→				if ((data as { error?: string }).error) {
101→					setTsError((data as { error?: string }).error || null);
102→				} else {
103→					setTsStatus(data);
