119→		rerender();
120→		fetch("/api/ngrok/status")
121→			.then((r) => {
122→				const ct = r.headers.get("content-type") || "";
123→				if (r.status === 404 || !ct.includes("application/json")) {
124→					setNgError("ngrok feature is not enabled. Rebuild with --features ngrok.");
125→					setNgStatus(null);
126→					setNgLoading(false);
127→					rerender();
128→					return null;
129→				}
130→				return r.json();
131→			})
132→			.then((data: NgrokStatus | null) => {
133→				if (!data) return;
134→				setNgStatus(data);
135→				setNgError(data.error || null);
136→				setNgLoading(false);
137→				setNgForm({
138→					enabled: Boolean(data.enabled),
139→					authtoken: "",
140→					clearAuthtoken: false,
141→					domain: data.domain || "",
142→				});
143→				rerender();
144→			})
145→			.catch((e: Error) => {
146→				setNgError(e.message);
147→				setNgLoading(false);
148→				rerender();
149→			});
150→	}
151→
152→	function setMode(mode: string): void {
153→		setConfiguring(true);
154→		setTsError(null);
155→		setTsWarning(null);
156→		setConfiguringMode(mode);
157→		rerender();
158→		fetch("/api/tailscale/configure", {
159→			method: "POST",
