298→	matrixStatus: MatrixStatus;
299→}
300→
301→function MatrixOwnershipCard({ channel, matrixStatus }: MatrixOwnershipCardProps): VNode {
302→	const retryingOwnership = useSignal(false);
303→	const retryOwnershipError = useSignal("");
304→	const ownershipMode = normalizeMatrixOwnershipMode(matrixStatus?.ownership_mode);
305→	const authMode = normalizeMatrixAuthMode(matrixStatus?.auth_mode);
306→	const recoveryState = String(matrixStatus?.recovery_state || "unknown");
307→	const deviceVerified = !!matrixStatus?.device_verified_by_owner;
308→	const ownershipError = String(matrixStatus?.ownership_error || "").trim();
309→	const approvalMatch = ownershipError.match(/https?:\/\/\S+/);
310→	const ownershipIssue =
311→		ownershipMode !== "moltis_owned" || ownershipError.length === 0
312→			? "none"
313→			: ownershipError.includes("requires browser approval to reset cross-signing")
314→				? "approval_required"
315→				: ownershipError.includes("incomplete secret storage")
316→					? "incomplete_secret_storage"
317→					: "generic_blocked";
318→	const modeTitle =
319→		ownershipIssue === "approval_required"
320→			? "Ownership approval required"
321→			: ownershipIssue !== "none"
322→				? "Moltis ownership blocked"
323→				: ownershipMode === "moltis_owned"
324→					? "Managed by Moltis"
325→					: "User-managed in Element";
326→	const modeText =
327→		ownershipIssue === "approval_required"
328→			? "This existing Matrix account can already chat, but Matrix needs one browser approval before Moltis can take over encryption ownership. Open the approval page, approve the reset, then retry ownership setup."
329→			: ownershipIssue === "incomplete_secret_storage"
330→				? "This account already has partial Matrix secure-backup state. Finish or repair it in Element, or switch this channel to user-managed mode."
331→				: ownershipIssue === "generic_blocked"
332→					? "Moltis could not take ownership of this Matrix account automatically. Repair the account in Element or switch this channel to user-managed mode."
333→					: authMode === "password" || authMode === "oidc"
334→						? matrixOwnershipModeGuidance(authMode, ownershipMode)
335→						: "Access token auth is always user-managed. If you want encrypted Matrix chats, reconnect this channel with OIDC or password auth so Moltis can create its own device.";
336→	const detailTitle =
337→		ownershipIssue === "approval_required"
338→			? "Browser approval pending"
339→			: ownershipError
340→				? "Ownership setup needs attention"
341→				: "";
342→	const detailText =
343→		ownershipIssue === "approval_required"
344→			? `Approve the reset while signed into ${matrixStatus?.user_id || "this Matrix account"} in the browser, then use the retry button here so Moltis can finish taking ownership.`
345→			: ownershipError;
346→	const approvalUrl = approvalMatch ? approvalMatch[0].replace(/[;),.]+$/, "") : "";
347→	const verificationText = deviceVerified ? "Device verified by owner" : "Device not yet verified by owner";
348→	const hasAccountDetails =
349→		!!String(channel.config?.homeserver || "").trim() ||
350→		!!String(matrixStatus?.user_id || "").trim() ||
351→		!!String(matrixStatus?.device_id || "").trim() ||
352→		!!String(matrixStatus?.device_display_name || channel.config?.device_display_name || "").trim();
353→
354→	function retryOwnershipSetup(): void {
355→		retryingOwnership.value = true;
356→		retryOwnershipError.value = "";
357→		sendRpc("channels.retry_ownership", {
358→			type: channelType(channel.type),
359→			account_id: channel.account_id,
360→		}).then((res) => {
361→			retryingOwnership.value = false;
362→			if (res?.ok) {
363→				showToast("Retrying Matrix ownership setup");
364→				loadChannels();
365→				return;
366→			}
367→			retryOwnershipError.value =
368→				(res?.error as { message?: string; detail?: string })?.message ||
369→				(res?.error as { detail?: string })?.detail ||
370→				"Failed to retry Matrix ownership setup.";
371→		});
372→	}
373→
374→	return (
375→		<div className="rounded-md border border-sky-600/30 bg-sky-50 px-3 py-2 text-xs text-sky-900">
376→			<div className="flex items-center gap-2">
377→				<div className="font-medium text-sky-800">{modeTitle}</div>
378→				<span className={`provider-item-badge ${deviceVerified ? "configured" : "oauth"}`}>{verificationText}</span>
379→			</div>
380→			<div className="mt-1 text-sky-900">{modeText}</div>
381→			<div className="mt-2 text-sky-900">
382→				Cross-signing:{" "}
383→				<span className="font-medium">{matrixStatus?.cross_signing_complete ? "ready" : "not ready"}</span>. Recovery:{" "}
384→				<span className="font-medium">{recoveryState}</span>.
385→			</div>
386→			{hasAccountDetails && (
387→				<details className="mt-2 rounded-md border border-sky-600/20 bg-sky-100/50 px-3 py-2">
388→					<summary className="cursor-pointer text-[11px] font-medium uppercase tracking-wide text-sky-800">
389→						Matrix account details
390→					</summary>
391→					<div className="mt-2 grid gap-2">
392→						<MatrixInfoRow label="Homeserver" value={channel.config?.homeserver || ""} copyLabel="Homeserver copied" />
393→						<MatrixInfoRow label="Matrix user" value={matrixStatus?.user_id || ""} copyLabel="Matrix user ID copied" />
394→						<MatrixInfoRow
395→							label="Device ID"
396→							value={matrixStatus?.device_id || ""}
397→							copyLabel="Matrix device ID copied"
398→						/>
399→						<MatrixInfoRow
400→							label="Device name"
401→							value={matrixStatus?.device_display_name || channel.config?.device_display_name || ""}
402→							copyLabel="Matrix device name copied"
403→						/>
404→					</div>
405→				</details>
406→			)}
407→			{ownershipIssue === "approval_required" && approvalUrl && (
408→				<div className="mt-2">
409→					<div className="flex flex-wrap gap-2">
410→						<a
411→							href={approvalUrl}
412→							target="_blank"
413→							rel="noreferrer"
414→							className="provider-btn provider-btn-sm"
415→							aria-label={`Open approval page for ${matrixStatus?.user_id || "this Matrix account"}`}
416→						>
417→							Open approval page for {matrixStatus?.user_id || "this account"}
418→						</a>
419→						<button
420→							type="button"
421→							className="provider-btn provider-btn-sm"
422→							onClick={retryOwnershipSetup}
423→							disabled={retryingOwnership.value}
424→						>
425→							{retryingOwnership.value ? "Retrying ownership setup..." : "Click here once you reset the account"}
426→						</button>
427→					</div>
428→					<div className="mt-2 text-[11px] text-sky-800">
429→						Make sure the browser page is signed into{" "}
430→						<span className="font-mono text-sky-800">{matrixStatus?.user_id || "the Matrix bot account"}</span>.
431→					</div>
432→					{retryOwnershipError.value && (
433→						<div className="mt-2 rounded-md border border-amber-500/30 bg-amber-500/10 px-3 py-2 text-amber-100">
434→							{retryOwnershipError.value}
435→						</div>
436→					)}
437→				</div>
438→			)}
439→			{detailTitle && (
440→				<div className="mt-2 rounded-md border border-amber-500/30 bg-amber-500/10 px-3 py-2 text-amber-100">
441→					<div className="font-medium text-amber-50">{detailTitle}</div>
442→					<div className="mt-1">{detailText}</div>
443→				</div>
444→			)}
445→		</div>
446→	);
447→}
