451→function senderSelectionKey(ch: Channel): string {
452→	return `${channelType(ch.type)}::${ch.account_id}`;
453→}
454→
455→function parseSenderSelectionKey(key: string): { type: string; account_id: string } {
456→	const idx = key.indexOf("::");
457→	if (idx < 0) return { type: "telegram", account_id: key };
458→	return {
459→		type: key.slice(0, idx) || "telegram",
460→		account_id: key.slice(idx + 2),
461→	};
462→}
