466→export function loadChannels(): void {
467→	fetchChannelStatus().then((res: unknown) => {
468→		const r = res as { ok?: boolean; payload?: { channels?: Channel[] } } | undefined;
469→		if (r?.ok) {
470→			const ch = r.payload?.channels || [];
471→			channels.value = ch;
472→			S.setCachedChannels(ch);
473→			updateNavCount("channels", ch.length);
474→		}
475→	});
476→}
