478→function loadSenders(): void {
479→	const selected = sendersAccount.value;
480→	if (!selected) {
481→		senders.value = [];
482→		return;
483→	}
484→	const parsed = parseSenderSelectionKey(selected);
485→	sendRpc<{ senders?: SenderEntry[] }>("channels.senders.list", {
486→		type: parsed.type,
487→		account_id: parsed.account_id,
488→	}).then((res) => {
489→		if (res?.ok) senders.value = (res.payload?.senders || []) as SenderEntry[];
490→	});
491→}
