536→	const matrixStatus = ch.extra?.matrix || null;
537→	const pendingVerifications = Array.isArray(matrixStatus?.pending_verifications)
538→		? matrixStatus.pending_verifications
539→		: [];
540→	const verificationStateLabel = matrixStatus?.verification_state || null;
541→	const showOwnershipCard =
542→		channelType(ch.type) === "matrix" &&
