553→					{ch.details && <span className="text-xs text-[var(--muted)]">{ch.details}</span>}
554→					{sessionLine && <span className="text-xs text-[var(--muted)]">{sessionLine}</span>}
555→					{channelType(ch.type) === "matrix" && verificationStateLabel && (
