560→							href={`https://t.me/${ch.account_id}`}
561→							target="_blank"
562→							className="text-xs text-[var(--accent)] underline"
563→						>
564→							t.me/{ch.account_id}
565→						</a>
566→					)}
567→				</div>
568→				<span className={`provider-item-badge ${statusClass}`}>{ch.status || "unknown"}</span>
569→				{modeLabel && <span className="tier-badge">{modeLabel}</span>}
570→			</div>
571→			{channelType(ch.type) === "matrix" && pendingVerifications.length > 0 && (
572→				<div className="rounded-md border border-emerald-500/30 bg-emerald-500/10 px-3 py-2 text-xs text-emerald-100">
