577→							<div className="text-emerald-200/90">
578→								Send <span className="font-mono">verify yes</span>, <span className="font-mono">verify no</span>,{" "}
579→								<span className="font-mono">verify show</span>, or <span className="font-mono">verify cancel</span> as a
580→								normal message in that same Matrix chat.
581→							</div>
582→						</div>
583→					))}
584→				</div>
585→			)}
586→			{showOwnershipCard && matrixStatus && <MatrixOwnershipCard channel={ch} matrixStatus={matrixStatus} />}
587→			<div className="flex gap-2">
588→				<button
589→					className="provider-btn provider-btn-sm provider-btn-secondary"
590→					title={`Edit ${ch.account_id || "channel"}`}
