594→				>
595→					Edit
596→				</button>
597→				<button
598→					className="provider-btn provider-btn-sm provider-btn-danger"
599→					title={`Remove ${ch.account_id || "channel"}`}
600→					onClick={onRemove}
601→				>
602→					Remove
603→				</button>
604→			</div>
605→		</div>
