674→					<span className="icon icon-whatsapp" /> Connect WhatsApp
675→				</button>
676→			)}
677→			{offered.has("nostr") && (
678→				<button
679→					className="provider-btn provider-btn-secondary inline-flex items-center gap-1.5"
680→					onClick={() => {
681→						if (connected.value) showAddNostr.value = true;
682→					}}
683→				>
684→					<span className="icon icon-nostr" /> Connect Nostr
685→				</button>
686→			)}
687→		</div>
688→	);
689→}
690→
691→// ── Channels tab ─────────────────────────────────────────────
692→
693→function ChannelsTab(): VNode {
694→	if (channels.value.length === 0) {
695→		return (
696→			<div className="text-center py-10">
697→				<div className="text-sm text-[var(--muted)] mb-4">No channels connected.</div>
698→				<div className="flex justify-center">
699→					<ConnectButtons />
700→				</div>
701→			</div>
702→		);
703→	}
704→	return (
705→		<>
706→			{channels.value.map((ch) => (
707→				<ChannelCard key={senderSelectionKey(ch)} channel={ch} />
708→			))}
709→		</>
710→	);
711→}
712→
713→// ── Sender row renderer ──────────────────────────────────────
714→
715→function renderSenderRow(s: SenderEntry, onAction: (identifier: string, action: string) => void): VNode {
716→	const identifier = s.username || s.peer_id;
717→	const lastSeenMs = s.last_seen ? s.last_seen * 1000 : 0;
718→	const usernameLabel = s.username ? (String(s.username).startsWith("@") ? s.username : `@${s.username}`) : "\u2014";
719→	const statusBadge = s.otp_pending ? (
720→		<span
721→			className="provider-item-badge cursor-pointer select-none"
722→			style={{ background: "var(--warning-bg, #fef3c7)", color: "var(--warning-text, #92400e)" }}
723→			onClick={() => {
724→				navigator.clipboard.writeText(s.otp_pending?.code ?? "").then(() => showToast("OTP code copied"));
725→			}}
726→		>
727→			OTP: <code className="text-xs">{s.otp_pending.code}</code>
728→		</span>
729→	) : (
730→		<span className={`provider-item-badge ${s.allowed ? "configured" : "oauth"}`}>
731→			{s.allowed ? "Allowed" : "Denied"}
732→		</span>
733→	);
734→	const actionBtn = s.allowed ? (
735→		<button className="provider-btn provider-btn-sm provider-btn-danger" onClick={() => onAction(identifier, "deny")}>
736→			Deny
737→		</button>
738→	) : (
739→		<button className="provider-btn provider-btn-sm" onClick={() => onAction(identifier, "approve")}>
740→			Approve
741→		</button>
742→	);
743→	return (
744→		<tr key={s.peer_id}>
745→			<td className="senders-td">{s.sender_name || s.peer_id}</td>
746→			<td className="senders-td" style={{ color: "var(--muted)" }}>
747→				{usernameLabel}
748→			</td>
749→			<td className="senders-td">{s.message_count}</td>
750→			<td className="senders-td" style={{ color: "var(--muted)", fontSize: "12px" }}>
751→				{lastSeenMs ? <time data-epoch-ms={String(lastSeenMs)}>{new Date(lastSeenMs).toISOString()}</time> : "\u2014"}
752→			</td>
753→			<td className="senders-td">{statusBadge}</td>
754→			<td className="senders-td">{actionBtn}</td>
755→		</tr>
756→	);
757→}
758→
759→// ── Senders tab ──────────────────────────────────────────────
760→
761→function SendersTab(): VNode {
762→	useEffect(() => {
763→		if (channels.value.length > 0 && !sendersAccount.value) {
764→			sendersAccount.value = senderSelectionKey(channels.value[0]);
765→		}
766→	}, [channels.value]);
767→
768→	useEffect(() => {
769→		loadSenders();
770→	}, [sendersAccount.value]);
771→
772→	if (channels.value.length === 0) {
773→		return <div className="text-sm text-[var(--muted)]">No channels configured.</div>;
774→	}
775→
776→	function onAction(identifier: string, action: string): void {
777→		const rpc = action === "approve" ? "channels.senders.approve" : "channels.senders.deny";
778→		const parsed = parseSenderSelectionKey(sendersAccount.value);
779→		sendRpc(rpc, {
780→			type: parsed.type,
781→			account_id: parsed.account_id,
782→			identifier,
783→		}).then(() => {
784→			loadSenders();
785→			loadChannels();
786→		});
787→	}
788→
789→	return (
790→		<div>
791→			<div style={{ marginBottom: "12px" }}>
792→				<label className="text-xs text-[var(--muted)]" style={{ marginRight: "6px" }}>
793→					Account:
794→				</label>
795→				<select
796→					style={{
797→						background: "var(--surface2)",
798→						color: "var(--text)",
799→						border: "1px solid var(--border)",
800→						borderRadius: "4px",
801→						padding: "4px 8px",
802→						fontSize: "12px",
803→					}}
804→					value={sendersAccount.value}
805→					onChange={(e) => {
806→						sendersAccount.value = (e.target as HTMLSelectElement).value;
807→					}}
808→				>
809→					{channels.value.map((ch) => (
810→						<option key={senderSelectionKey(ch)} value={senderSelectionKey(ch)}>
811→							{ch.name || ch.account_id}
812→						</option>
813→					))}
814→				</select>
815→			</div>
816→			{senders.value.length === 0 && (
817→				<div className="text-sm text-[var(--muted)] senders-empty">No messages received yet for this account.</div>
818→			)}
819→			{senders.value.length > 0 && (
820→				<table className="senders-table">
821→					<thead>
822→						<tr>
823→							<th className="senders-th">Sender</th>
824→							<th className="senders-th">Username</th>
825→							<th className="senders-th">Messages</th>
826→							<th className="senders-th">Last Seen</th>
827→							<th className="senders-th">Status</th>
828→							<th className="senders-th">Action</th>
829→						</tr>
830→					</thead>
831→					<tbody>{senders.value.map((s) => renderSenderRow(s, onAction))}</tbody>
832→				</table>
833→			)}
834→		</div>
835→	);
836→}
837→
838→// ── Channel event handlers ───────────────────────────────────
839→
840→function handleWhatsAppPairingEvent(p: ChannelEvent): void {
841→	if (p.kind === "pairing_qr_code" && p.account_id === waPairingAccountId.value) {
842→		waQrData.value = p.qr_data || null;
843→		waQrSvg.value = p.qr_svg || null;
844→	}
845→	if (p.kind === "pairing_complete" && p.account_id === waPairingAccountId.value) {
846→		showToast("WhatsApp connected!");
847→		showAddWhatsApp.value = false;
848→		waPairingAccountId.value = null;
849→		waQrData.value = null;
850→		waQrSvg.value = null;
851→		loadChannels();
852→	}
853→	if (p.kind === "pairing_failed" && p.account_id === waPairingAccountId.value) {
854→		waPairingError.value = p.reason || "Pairing failed";
855→	}
856→}
857→
858→function handleChannelEvent(_payload: unknown): void {
859→	const p = _payload as ChannelEvent;
860→	if (p.kind === "otp_resolved") {
861→		loadChannels();
862→	}
863→	handleWhatsAppPairingEvent(p);
864→	if (p.kind === "pairing_complete" || p.kind === "account_disabled") {
865→		loadChannels();
866→	}
867→	const selected = parseSenderSelectionKey(sendersAccount.value || "");
868→	if (
869→		activeTab.value === "senders" &&
870→		selected.account_id === p.account_id &&
871→		selected.type === channelType(p.channel_type) &&
872→		(p.kind === "inbound_message" || p.kind === "otp_challenge" || p.kind === "otp_resolved")
873→	) {
874→		loadSenders();
875→	}
876→}
877→
878→// ── Main page component ──────────────────────────────────────
879→
880→function ChannelsPageComponent(): VNode {
881→	useEffect(() => {
882→		S.setRefreshChannelsPage(loadChannels);
883→		// Use prefetched cache for instant render
884→		if (S.cachedChannels !== null) channels.value = S.cachedChannels as Channel[];
885→		if (connected.value) loadChannels();
886→
887→		const unsub = onEvent("channel", handleChannelEvent);
888→		S.setChannelEventUnsub(unsub);
889→
890→		return () => {
891→			S.setRefreshChannelsPage(null);
892→			if (unsub) unsub();
893→			S.setChannelEventUnsub(null);
894→		};
895→	}, [connected.value]);
896→
897→	return (
898→		<div className="flex-1 flex flex-col min-w-0 p-4 gap-4 overflow-y-auto">
899→			<div className="flex items-center gap-3 flex-wrap">
900→				<h2 className="text-lg font-medium text-[var(--text-strong)]">Channels</h2>
901→				<div style={{ display: "flex", gap: "4px", marginLeft: "12px" }}>
902→					<button
903→						className="session-action-btn"
904→						style={activeTab.value === "channels" ? { fontWeight: 600 } : undefined}
905→						onClick={() => {
906→							activeTab.value = "channels";
907→						}}
908→					>
909→						Channels
910→					</button>
911→					<button
912→						className="session-action-btn"
913→						style={activeTab.value === "senders" ? { fontWeight: 600 } : undefined}
914→						onClick={() => {
915→							activeTab.value = "senders";
916→						}}
917→					>
918→						Senders
919→					</button>
920→				</div>
921→				{activeTab.value === "channels" && channels.value.length > 0 && <ConnectButtons />}
922→			</div>
923→			{activeTab.value === "channels" && <ChannelStorageNotice />}
924→			{activeTab.value === "channels" ? <ChannelsTab /> : <SendersTab />}
925→			<AddTelegramModal />
926→			<AddTeamsModal />
927→			<AddDiscordModal />
928→			<AddSlackModal />
929→			<AddMatrixModal />
930→			<AddNostrModal />
931→			<AddWhatsAppModal />
932→			<EditChannelModal />
933→			<ConfirmDialog />
934→		</div>
935→	);
936→}
937→
938→// ── Mount / unmount exports ──────────────────────────────────
939→
940→let _channelsContainer: HTMLElement | null = null;
941→
942→export function initChannels(container: HTMLElement): void {
943→	_channelsContainer = container;
944→	container.style.cssText = "flex-direction:column;padding:0;overflow:hidden;";
945→	activeTab.value = "channels";
946→	showAddTelegram.value = false;
947→	showAddTeams.value = false;
948→	showAddDiscord.value = false;
949→	showAddSlack.value = false;
950→	showAddMatrix.value = false;
951→	showAddNostr.value = false;
952→	showAddWhatsApp.value = false;
953→	editingChannel.value = null;
954→	sendersAccount.value = "";
955→	senders.value = [];
956→	render(<ChannelsPageComponent />, container);
957→}
958→
959→export function teardownChannels(): void {
960→	S.setRefreshChannelsPage(null);
961→	if (S.channelEventUnsub) {
962→		S.channelEventUnsub();
963→		S.setChannelEventUnsub(null);
964→	}
965→	if (_channelsContainer) render(null, _channelsContainer);
966→	_channelsContainer = null;
967→}
