/** Channel config fields (union of all channel types). */
export interface ChannelConfig {
	// Common
	token?: string;
	dm_policy?: string;
	mention_mode?: string;
	allowlist?: string[];
	model?: string;
	model_provider?: string;
	// Teams
	app_id?: string;
	app_password?: string;
	webhook_secret?: string;
	stream_mode?: string;
	reply_style?: string;
	welcome_card?: boolean;
	bot_name?: string;
	// Slack
	bot_token?: string;
	app_token?: string;
	connection_mode?: string;
	group_policy?: string;
	signing_secret?: string;
	channel_allowlist?: string[];
	// Matrix
	homeserver?: string;
	user_id?: string;
	password?: string | null;
	access_token?: string;
	device_id?: string;
	device_display_name?: string | null;
	ownership_mode?: string;
	room_policy?: string;
	auto_join?: string;
	user_allowlist?: string[];
	room_allowlist?: string[];
